public function get_my_evaluations($username)
    {
        $this->db->from('ev_done');
        $this->db->where('w1', $username);
        $this->db->order_by('w18', 'DESC'); // Show newest first
        return $this->db->get()->result_array();
    }

    /**
     * Get a single evaluation record by its ID,
     * ensuring it belongs to the specified employee.
     * @param int $id The primary ID of the ev_done record
     * @param string $username The employee's username (for security)
     * @return array|null A single evaluation record or null
     */
    public function get_single_evaluation($id, $username)
    {
        $this->db->from('ev_done');
        $this->db->where('id', $id);
        $this->db->where('w1', $username); // Security check
        $this->db->limit(1);
        return $this->db->get()->row_array();
    }
        function get_daily_stoperes_update_admin(){
        date_default_timezone_set('Asia/Riyadh');
        $d=date("Y/m/d");
        $sql = "select * from ev_done;";
        $query = $this->db->query($sql);
        return $query->result_array();
      }


      function get_report_daily_stoperes_date_admin($s,$s1){  
      
         $sql="SELECT * FROM evaluation WHERE day between '$s' and '$s1';";
         $query = $this->db->query($sql);
        return $query->result_array();
        }

          function get_emp_data($id){
        $sql = "select * from ev_emp where m1='$id';";
        $query = $this->db->query($sql);
        return $query->row_array();
    }







    public function insert_or_update_attribution($data)
{
    // Adjust the unique key check as needed — here using n1 + project_id
    $this->db->where('n1', $data['n1']);
    $this->db->where('project_id', $data['project_id']);
    $existing = $this->db->get('attribution')->row();

    if ($existing) {
        $this->db->where('id', $existing->id);
        $this->db->update('attribution', $data);
    } else {
        $this->db->insert('attribution', $data);
    }
}
