public function update_all_attribution_tables($p, $id, $random_code, $code_name)
{
    // أسماء الجداول اللي تحتاج التحديث
    $tables = [
        'attribution',
        'attribution1',
        'attribution2',
        'attribution3',
        'attribution4',
        'attribution5',
        'attribution6',
        'attribution7',
        'attribution8',
        'attribution9',
        'attribution10',
        'attribution11',
        'attribution12',
        'attribution13',
        'attribution14',
        'attribution15'
    ];

    // البيانات المراد تحديثها
    $data = [
        'n3' => $random_code,
        'h7' => $code_name
    ];

    // تحديث كل الجداول
    foreach ($tables as $table) {
        $this->db->where('project_id', $p); // تأكد من اسم عمود المشروع
        $this->db->where('n3', $id);
        $this->db->update($table, $data);
    }

    return true;
}




