public function get_reimbursements_with_targets($from_date, $to_date, $project_id = null) {
    $month_year = date('Y/m', strtotime($from_date));

    $this->db->query("SET SESSION sql_mode=(SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY',''))"); // تعطيل قيود التجميع إن لزم

    $sql = "
        SELECT 
            er.project AS project_name,
            COUNT(*) AS total_payments,
            SUM(er.n2) AS total_amount,
            COALESCE(targets.total_target, 0) AS total_target,
            CASE 
                WHEN COALESCE(targets.total_target, 0) > 0 
                THEN ROUND(SUM(er.n2) / targets.total_target * 100, 2)
                ELSE 0
            END AS achievement_percentage
        FROM 
            employee_reimbursements er
        LEFT JOIN (
            SELECT 
                tr.n5,
                SUM(tr.n8) AS total_target
            FROM 
                traget_report tr
            WHERE 
                tr.date = ?
            GROUP BY tr.n5
        ) targets ON targets.n5 = er.project_id
        WHERE 
            er.status = 1
            AND er.n8 BETWEEN ? AND ?
    ";

    $params = [$month_year, $from_date, $to_date];

    if (!empty($project_id)) {
        $sql .= " AND er.project_id = ?";
        $params[] = $project_id;
    }

    $sql .= " GROUP BY er.project ORDER BY achievement_percentage DESC";

    return $this->db->query($sql, $params)->result_array();
}

