    $params = [$month_year, $from_date, $to_date, $project_id];

    return $this->db->query($sql, $params)->result_array();
}

public function get_supervisor_performance_fast($month_year, $supervisor_id = null)
{
    // $month_year بصيغة yyyy/mm (مثل 2025/08)
    $filters_targets = '';
    $filters_paid_x3 = '';
    $filters_paid_n6 = '';

    if (!empty($supervisor_id)) {
        $filters_targets = " AND t.n4 = ? ";
        $filters_paid_x3 = " AND e.x3 = ? ";
        $filters_paid_n6 = " AND e.n6 = ? ";
    }

    $sql = "
        SELECT
            tgt.supervisor_id,
            tgt.supervisor_name,
            tgt.project_code,
            tgt.project_name,
            tgt.employee_count,
            tgt.project_target AS total_target,
            COALESCE(paid.total_paid, 0) AS total_paid,
            CASE
                WHEN tgt.project_target > 0
                    THEN ROUND(COALESCE(paid.total_paid, 0) / tgt.project_target * 100, 2)
                ELSE 0
            END AS achievement_percentage
        FROM
        (
            SELECT
                t.n4 AS supervisor_id,                  -- رقم المشرف
                MAX(t.n3) AS supervisor_name,           -- اسم المشرف
                TRIM(t.n5) AS project_code,             -- كود المشروع
                MAX(TRIM(t.n6)) AS project_name,        -- اسم المشروع
                COUNT(DISTINCT t.n2) AS employee_count, -- عدد الموظفين ضمن هذا المشروع
                SUM(t.n8) AS project_target             -- مستهدف المشروع لهذا المشرف
            FROM traget_report t
            WHERE t.`date` = ? {$filters_targets}
            GROUP BY t.n4, TRIM(t.n5)
        ) AS tgt
        LEFT JOIN
        (
            SELECT sup_id, project_code, SUM(amount) AS total_paid
            FROM (
                /* مسار x3: سداد المشرف حسب x3 */
                SELECT
                    TRIM(e.x3) AS sup_id,
                    TRIM(e.project_id) AS project_code,
                    SUM(e.n2) AS amount
                FROM employee_reimbursements e
                WHERE e.status = 1
                  AND e.x3 IS NOT NULL AND e.x3 <> ''
                  AND e.project_id IS NOT NULL AND e.project_id <> ''
                  AND DATE_FORMAT(e.n8, '%Y/%m') = ? {$filters_paid_x3}
                GROUP BY TRIM(e.x3), TRIM(e.project_id)

                UNION ALL

                /* مسار n6: سداد المشرف حسب n6 مع استبعاد السجلات التي n6 = x3 */
                SELECT
                    TRIM(e.n6) AS sup_id,
                    TRIM(e.project_id) AS project_code,
                    SUM(e.n2) AS amount
                FROM employee_reimbursements e
                WHERE e.status = 1
                  AND e.n6 IS NOT NULL AND e.n6 <> ''
                  AND e.project_id IS NOT NULL AND e.project_id <> ''
                  AND DATE_FORMAT(e.n8, '%Y/%m') = ?
                  AND (e.n6 <> e.x3 OR e.x3 IS NULL OR e.x3 = '') {$filters_paid_n6}
                GROUP BY TRIM(e.n6), TRIM(e.project_id)
            ) u
            GROUP BY sup_id, project_code
        ) AS paid
          ON paid.sup_id = tgt.supervisor_id
         AND paid.project_code = tgt.project_code
        ORDER BY achievement_percentage DESC
    ";

    // ترتيب الباراميترات بحسب الظهور:
    $binds = [];
    // traget_report: date [, supervisor_id]
    $binds[] = $month_year;
    if (!empty($supervisor_id)) $binds[] = $supervisor_id;

    // reimbursements x3: month [, supervisor_id]
    $binds[] = $month_year;
    if (!empty($supervisor_id)) $binds[] = $supervisor_id;

    // reimbursements n6: month [, supervisor_id]
    $binds[] = $month_year;
    if (!empty($supervisor_id)) $binds[] = $supervisor_id;

    return $this->db->query($sql, $binds)->result_array();
}



