public function get_supervisor_performance_fast1($month_year) {
    $project_id = $this->session->userdata('project'); // كود المشروع الحالي

    $sql = "
        SELECT 
            t.n3 AS supervisor_name,
            t.n6 AS project_name,
            COUNT(DISTINCT t.n2) AS employee_count,
            SUM(t.n8) AS total_target,
            COALESCE(SUM(r.total_paid), 0) AS total_paid,
            CASE 
                WHEN SUM(t.n8) > 0 THEN ROUND(COALESCE(SUM(r.total_paid), 0) / SUM(t.n8) * 100, 2)
                ELSE 0
            END AS achievement_percentage
        FROM 
            traget_report t
        LEFT JOIN (
            SELECT 
                e.n6 AS employee_code,
                SUM(e.n2) AS total_paid
            FROM 
                employee_reimbursements e
            WHERE 
                e.status = 1 
                AND DATE_FORMAT(e.n8, '%Y/%m') = ?
            GROUP BY 
                e.n6
        ) AS r ON r.employee_code = t.n2
        WHERE 
            t.date = ?
            AND t.n5 = ?
        GROUP BY 
            t.n3, t.n6
        ORDER BY 
            achievement_percentage DESC
    ";

    return $this->db->query($sql, [$month_year, $month_year, $project_id])->result_array();
}

