    public function get_monthly_targets_map($year, $month)
{
    $ym = sprintf('%04d/%02d', $year, $month);

    $this->db->select('n5 AS project_id, SUM(n8) AS target_amount');
    $this->db->from('traget_report');
    $this->db->where('date', $ym); // نفس الصيغة yyyy/mm
    $this->db->group_by('n5');

    $rows = $this->db->get()->result_array();
    $map = [];
    foreach ($rows as $r) {
        $map[(int)$r['project_id']] = (float)$r['target_amount'];
    }
    return $map;
}

public function get_daily_reimbursements_by_project($dateISO)
{
    if (empty($dateISO) || !preg_match('/^\d{4}-\d{2}-\d{2}$/', $dateISO)) {
        return [];
    }
    $this->db->select('er.project_id, SUM(er.n2) AS total_amount');
    $this->db->from('employee_reimbursements er');
    $this->db->where('DATE(STR_TO_DATE(er.n8, "%Y/%m/%d")) =', $dateISO);
    $this->db->where('er.status', 1);
    $this->db->group_by('er.project_id');
    $this->db->order_by('total_amount', 'DESC');

    return $this->db->get()->result_array();
}

public function get_monthly_actuals_map($year, $month)
{
    // بداية ونهاية الشهر
    $period_start = sprintf('%04d-%02d-01', $year, $month);
    $period_end   = date('Y-m-d', strtotime($period_start.' +1 month'));

    $this->db->select('er.project_id, SUM(er.n2) AS total_amount');
    $this->db->from('employee_reimbursements er');
    $this->db->where('STR_TO_DATE(er.n8, "%Y/%m/%d") >=', $period_start);
    $this->db->where('STR_TO_DATE(er.n8, "%Y/%m/%d") <',  $period_end);
    $this->db->where('er.status', 1);
    $this->db->group_by('er.project_id');

    $rows = $this->db->get()->result_array();
    $map = [];
    foreach ($rows as $r) {
        $map[(int)$r['project_id']] = (float)$r['total_amount'];
    }
    return $map;
}

