    /** إرجاع أسماء المشاريع (n6). إن تم تمرير منطقة، يفلتر حسبها */
    public function get_projects1(string $region = ''): array
    {
        $this->db->distinct()
            ->select('n6 AS project_name', false)
            ->from('sub');
        if ($region !== '') {
            $this->db->where('n7', $region);
        }
        return $this->db->order_by('n6','ASC')->get()->result_array();
    }

    /** إرجاع المشرفين (id = n2, name = n1). إن تم تمرير منطقة، يفلتر حسبها */
    public function get_supervisors1(string $region = ''): array
    {
        $this->db->distinct()
            ->select('n2 AS supervisor_id, n1 AS supervisor_name', false)
            ->from('sub');
        if ($region !== '') {
            $this->db->where('n7', $region);
        }
        return $this->db->order_by('n1','ASC')->get()->result_array();
    }

    /* ==========================================
     * التقرير التفصيلي (مشرف/مشروع) مع الحسابات
     * ========================================== */

    /**
     * - target_amount: SUM(traget_report.n8) لشهر محدد (Y/m) على (n4=sub.n2, n5=sub.n5) بعد التطبيع
     * - paid_amount  : SUM(employee_reimbursements.n2) لنفس الشهر من n8 (Y/m/dd)
     *                  مع شرط السداد: `status = 1`
     *                  ومع منع الازدواج عندما x3 = n6 بعد التطبيع
     * - achievement_percent = paid/target*100
     *
     * فلاتر: region(n7), project_name(n6), supervisor(n2), q, year, month
     * + شرط إضافي: TRIM(sub.n8) = 'Y/m'
     */
    public function get_rows(array $filters = []): array
    {
        date_default_timezone_set('Asia/Riyadh');

        $year       = !empty($filters['year'])  ? (int)$filters['year']  : (int)date('Y');
        $month      = !empty($filters['month']) ? (int)$filters['month'] : (int)date('m');
        $ym         = sprintf('%04d/%02d', $year, $month); // yyyy/mm
        $like_month = $ym . '/%';                          // yyyy/mm/%

        // مستهدفات الشهر المحدد: نطبع n4 إلى رقم (n4n) ونستخدم n5 بعد TRIM
        $target_subq = "(SELECT
                            CAST(TRIM(n4) AS UNSIGNED) AS n4n,
                            TRIM(n5) AS n5,
                            SUM(n8) AS target_sum
                         FROM traget_report
                         WHERE `date` = " . $this->db->escape($ym) . "
                         GROUP BY CAST(TRIM(n4) AS UNSIGNED), TRIM(n5)) t";

        // سدادات الشهر المحدد: شرط status = 1 + منع الازدواج عندما x3 = n6 (بعد التطبيع)
        $paid_subq = "(
            SELECT project_id, super_norm, SUM(amount) AS paid_sum
            FROM (
                -- الذراع الأول: مشرف واحد لكل سجل (x3 إن وُجد، وإلا n6)
                SELECT
                    TRIM(project_id) AS project_id,
                    CASE
                        WHEN COALESCE(NULLIF(TRIM(x3), ''), NULL) IS NOT NULL
                            THEN CAST(TRIM(x3) AS UNSIGNED)
                        ELSE CAST(TRIM(n6) AS UNSIGNED)
                    END AS super_norm,
                    n2 AS amount
                FROM employee_reimbursements
                WHERE n8 LIKE " . $this->db->escape($like_month) . "
                  AND `status` = 1

                UNION ALL

                -- الذراع الثاني: n6 فقط إذا كان مختلفًا عن x3 بعد التطبيع وكلاهما غير فارغين
                SELECT
                    TRIM(project_id) AS project_id,
                    CAST(TRIM(n6) AS UNSIGNED) AS super_norm,
                    n2 AS amount
                FROM employee_reimbursements
                WHERE n8 LIKE " . $this->db->escape($like_month) . "
                  AND `status` = 1
                  AND COALESCE(NULLIF(TRIM(n6), ''), NULL) IS NOT NULL
                  AND COALESCE(NULLIF(TRIM(x3), ''), NULL) IS NOT NULL
                  AND CAST(TRIM(n6) AS UNSIGNED) <> CAST(TRIM(x3) AS UNSIGNED)
            ) u
            WHERE super_norm IS NOT NULL AND super_norm <> 0
            GROUP BY project_id, super_norm
        ) r";

        $this->db->select("
                s.n1, s.n2, s.n3, s.n4, s.n5, s.n6, s.n7, s.n8,
                COALESCE(t.target_sum, 0) AS target_amount,
                COALESCE(r.paid_sum,   0) AS paid_amount,
                CASE
                    WHEN COALESCE(t.target_sum,0) > 0
                    THEN ROUND((COALESCE(r.paid_sum,0) / t.target_sum) * 100, 2)
                    ELSE 0
                END AS achievement_percent
            ", false)
            ->from('sub s')
            // شرط الشهر/السنة من sub.n8 بصيغة yyyy/mm
            ->where("TRIM(s.n8) = " . $this->db->escape($ym))
            // الربط بالمستهدفات على القيم المُطبّعة
            ->join($target_subq, 't.n4n = CAST(TRIM(s.n2) AS UNSIGNED) AND t.n5 = TRIM(s.n5)', 'left')
            // الربط بالسدادات على القيم المُطبّعة
            ->join($paid_subq,   'r.project_id = TRIM(s.n5) AND r.super_norm = CAST(TRIM(s.n2) AS UNSIGNED)', 'left');

        // فلاتر الواجهة
        if (!empty($filters['region']))       { $this->db->where('s.n7', $filters['region']); }
        if (!empty($filters['project_name'])) { $this->db->where('s.n6', $filters['project_name']); }
        if (!empty($filters['supervisor']))   { $this->db->where('s.n2', $filters['supervisor']); }
        if (!empty($filters['q'])) {
            $q = $this->db->escape_like_str($filters['q']);
            $this->db->group_start()
                     ->like('s.n1', $q, 'both', false)
                     ->or_like('s.n3', $q, 'both', false)
                     ->group_end();
        }

        // ترتيب: نسبة التحقيق، ثم اسم المشروع، ثم اسم المشرف
        return $this->db
            ->order_by('achievement_percent', 'DESC')
            ->order_by('s.n6', 'ASC')
            ->order_by('s.n1', 'ASC')
            ->get()->result_array();
    }

    /* =================================
     * ملخص المناطق (أعلى التقرير)
     * ================================= */

    /**
     * ملخّص على مستوى المناطق: region, supervisors_count, projects_count, target_total, paid_total, achievement_percent
     * يحترم فلاتر: region / project_name / supervisor / q / year / month
     * + شرط إضافي: TRIM(sub.n8) = 'Y/m'
     * SQL خام لتفادي مشاكل الأقواس.
     */
    public function get_region_summary(array $filters = []): array
    {
        date_default_timezone_set('Asia/Riyadh');

        $year       = !empty($filters['year'])  ? (int)$filters['year']  : (int)date('Y');
        $month      = !empty($filters['month']) ? (int)$filters['month'] : (int)date('m');
        $ym         = sprintf('%04d/%02d', $year, $month);
        $like_month = $ym . '/%';

        // WHERE للفلاتر على sub (+ شرط الشهر/السنة من sub.n8)
        $w = [];
        $w[] = "TRIM(s.n8) = " . $this->db->escape($ym); // ← جديد
        if (!empty($filters['region']))       { $w[] = "s.n7 = " . $this->db->escape($filters['region']); }
        if (!empty($filters['project_name'])) { $w[] = "s.n6 = " . $this->db->escape($filters['project_name']); }
        if (!empty($filters['supervisor']))   { $w[] = "s.n2 = " . $this->db->escape($filters['supervisor']); }
        if (!empty($filters['q'])) {
            $q = $this->db->escape_like_str($filters['q']);
            $w[] = "(s.n1 LIKE '%{$q}%' ESCAPE '!' OR s.n3 LIKE '%{$q}%' ESCAPE '!')";
        }
        $where_sql = "WHERE " . implode(' AND ', $w);

        $sql = "
            SELECT
                b.region,
                COUNT(DISTINCT b.super_id)  AS supervisors_count,
                COUNT(DISTINCT b.proj_name) AS projects_count,
                COALESCE(SUM(t.target_sum),0) AS target_total,
                COALESCE(SUM(r.paid_sum),0)   AS paid_total,
                CASE
                    WHEN COALESCE(SUM(t.target_sum),0) > 0
                    THEN ROUND(COALESCE(SUM(r.paid_sum),0) / COALESCE(SUM(t.target_sum),0) * 100, 2)
                    ELSE 0
                END AS achievement_percent
            FROM (
                SELECT DISTINCT
                       CAST(TRIM(s.n2) AS UNSIGNED) AS super_id_norm,
                       TRIM(s.n2) AS super_id,
                       TRIM(s.n5) AS proj_id,
                       TRIM(s.n6) AS proj_name,
                       TRIM(s.n7) AS region
                FROM sub s
                {$where_sql}
            ) b
            LEFT JOIN (
                SELECT
                    CAST(TRIM(n4) AS UNSIGNED) AS n4n,
                    TRIM(n5) AS n5,
                    SUM(n8) AS target_sum
                FROM traget_report
                WHERE `date` = " . $this->db->escape($ym) . "
                GROUP BY CAST(TRIM(n4) AS UNSIGNED), TRIM(n5)
            ) t ON t.n4n = b.super_id_norm AND t.n5 = b.proj_id
            LEFT JOIN (
                SELECT project_id, super_norm, SUM(amount) AS paid_sum
                FROM (
                    -- الذراع الأول: مشرف واحد لكل سجل (x3 إن وُجد، وإلا n6)
                    SELECT
                        TRIM(project_id) AS project_id,
                        CASE
                            WHEN COALESCE(NULLIF(TRIM(x3), ''), NULL) IS NOT NULL
                                THEN CAST(TRIM(x3) AS UNSIGNED)
                            ELSE CAST(TRIM(n6) AS UNSIGNED)
                        END AS super_norm,
                        n2 AS amount
                    FROM employee_reimbursements
                    WHERE n8 LIKE " . $this->db->escape($like_month) . "
                      AND `status` = 1

                    UNION ALL

                    -- الذراع الثاني: n6 فقط إذا كان مختلفًا عن x3 بعد التطبيع
                    SELECT
                        TRIM(project_id) AS project_id,
                        CAST(TRIM(n6) AS UNSIGNED) AS super_norm,
                        n2 AS amount
                    FROM employee_reimbursements
                    WHERE n8 LIKE " . $this->db->escape($like_month) . "
                      AND `status` = 1
                      AND COALESCE(NULLIF(TRIM(n6), ''), NULL) IS NOT NULL
                      AND COALESCE(NULLIF(TRIM(x3), ''), NULL) IS NOT NULL
                      AND CAST(TRIM(n6) AS UNSIGNED) <> CAST(TRIM(x3) AS UNSIGNED)
                ) u
                WHERE super_norm IS NOT NULL AND super_norm <> 0
                GROUP BY project_id, super_norm
            ) r ON r.project_id = b.proj_id AND r.super_norm = b.super_id_norm
            GROUP BY b.region
            ORDER BY achievement_percent DESC
        ";

        return $this->db->query($sql)->result_array();
    }












    


        public function get_monthly_reimbursements_by_project($year = null, $month = null)
{
    if (!$year)  { $year  = date('Y'); }
    if (!$month) { $month = date('m'); }

    $period_start = sprintf('%04d-%02d-01', $year, $month);
    $period_end   = date('Y-m-d', strtotime($period_start.' +1 month'));

    $this->db->select('er.project_id, SUM(er.n2) AS total_amount');
    $this->db->from('employee_reimbursements er');
    $this->db->where('STR_TO_DATE(er.n8, "%Y/%m/%d") >=', $period_start);
    $this->db->where('STR_TO_DATE(er.n8, "%Y/%m/%d") <',  $period_end);
    $this->db->where('er.status', 1); // الشرط الجديد
    $this->db->group_by('er.project_id');
    $this->db->order_by('total_amount', 'DESC');

    return $this->db->get()->result_array();
}




