    function createcsv12541251125215411111($billfold){
    $this->load->helper('download');

    $query = $this->db->query("SELECT * FROM $billfold");
    $rows = $query->result_array();

    $output = "";

    if (!empty($rows)) {
        // أسماء الأعمدة
        $headers = array_keys($rows[0]);
        $output .= implode(",", $headers) . "\r\n";

        // صفوف البيانات مع تحويل كل قيمة إلى نص
        foreach ($rows as $row) {
            $line = [];
            foreach ($row as $value) {
                $escaped = str_replace('"', '""', $value); // في حال وجود علامات اقتباس
                $line[] = '="' . $escaped . '"'; // صيغة النص
            }
            $output .= implode(",", $line) . "\r\n";
        }
    }

    $filename = "billfold.csv";
    force_download($filename, "\xEF\xBB\xBF" . $output);
}


public function redistribute_clients_balanced() {
    // 1. جلب الموظفين المؤهلين
    $employees = $this->db->query("SELECT username FROM users WHERE project = 3 AND type = 1")->result_array();

    if (empty($employees)) {
        echo "لا يوجد موظفين متاحين.";
        return;
    }

    // تحويل الموظفين إلى قائمة معرفات
    $employee_ids = array_column($employees, 'username');

    // تهيئة مصفوفة لتتبع مجموع المديونية لكل موظف
    $employee_loads = [];
    foreach ($employee_ids as $id) {
        $employee_loads[$id] = 0;
    }

    // 2. جلب جميع العملاء المراد توزيعهم مع مديونياتهم
    $clients = $this->db->query("SELECT id, h1 FROM attribution6_test")->result_array();

    if (empty($clients)) {
        echo "لا يوجد عملاء.";
        return;
    }

    // 3. ترتيب العملاء حسب المديونية من الأكبر إلى الأصغر
    usort($clients, function ($a, $b) {
        return $b['h1'] <=> $a['h1'];
    });

    // 4. توزيع العملاء على الموظف صاحب أقل مديونية حالية
    foreach ($clients as $client) {
        // إيجاد الموظف الأقل حملاً
        $assigned_employee = array_keys($employee_loads, min($employee_loads))[0];

        // تحديث العميل
        $this->db->where('id', $client['id']);
        $this->db->update('attribution6_test', ['n3' => $assigned_employee]);

        // تحديث إجمالي مديونية الموظف
        $employee_loads[$assigned_employee] += floatval($client['h1']);
    }

   redirect('users/distribution_report');
}

public function redistribute_all_clients() {
    // 1. جلب الموظفين من المشروع 6 والنوع 1 فقط
    $employees = $this->db->query("SELECT username FROM users WHERE project = 3 AND type = 1")->result_array();

    if (empty($employees)) {
        echo "لا يوجد موظفين في المشروع رقم 6 بالنوع 1";
        return;
    }

    // تحويل الموظفين إلى مصفوفة بسيطة
    $employee_ids = array_column($employees, 'username');
    $employee_count = count($employee_ids);

    // 2. جلب جميع العملاء من جدول attribution6_test (سواء موزعين أو لا)
    $clients = $this->db->query("SELECT id FROM attribution6_test")->result_array();

    if (empty($clients)) {
        echo "لا يوجد عملاء لإعادة توزيعهم";
        return;
    }

    // 3. إعادة توزيع العملاء بالتساوي
    $i = 0;
    foreach ($clients as $client) {
        $employee_id = $employee_ids[$i % $employee_count]; // توزيع دائري
        $this->db->where('id', $client['id']);
        $this->db->update('attribution6_test', ['n3' => $employee_id]);
        $i++;
    }

    redirect('users/distribution_report');
}


public function get_employees_distribution_report_grouped_by_product()
{
    $sql = "
        SELECT 
            a.product_type,
            a.n3 AS employee_number,
            u.name AS employee_name,
            COUNT(*) AS total_clients,
            SUM(a.h1) AS total_debt,
            SUM(CASE WHEN a.status_com = 'معلوم' THEN 1 ELSE 0 END) AS known_clients,
            SUM(CASE WHEN a.status_com = 'مجهول' THEN 1 ELSE 0 END) AS unknown_clients,

            -- شرائح المديونية
            SUM(CASE WHEN a.h1 < 50000 THEN 1 ELSE 0 END) AS debt_below_50k,
            SUM(CASE WHEN a.h1 >= 50000 AND a.h1 < 100000 THEN 1 ELSE 0 END) AS debt_50k_to_100k,
            SUM(CASE WHEN a.h1 >= 100000 AND a.h1 < 150000 THEN 1 ELSE 0 END) AS debt_100k_to_150k,
            SUM(CASE WHEN a.h1 >= 150000 THEN 1 ELSE 0 END) AS debt_above_150k,

            -- توزيع الجنسيات
            SUM(CASE WHEN a.id_type = 'هوية مواطن' THEN 1 ELSE 0 END) AS national_saudi,
            SUM(CASE WHEN a.id_type = 'هوية مقيم' THEN 1 ELSE 0 END) AS national_resident,
            SUM(CASE WHEN a.id_type NOT IN ('هوية مواطن', 'هوية مقيم') THEN 1 ELSE 0 END) AS national_others,

            -- النسب المئوية للجنسية
            ROUND(SUM(CASE WHEN a.id_type = 'هوية مواطن' THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) AS percent_saudi,
            ROUND(SUM(CASE WHEN a.id_type = 'هوية مقيم' THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) AS percent_resident,
            ROUND(SUM(CASE WHEN a.id_type NOT IN ('هوية مواطن', 'هوية مقيم') THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) AS percent_others,

            -- عملاء الرواتب
            SUM(CASE WHEN a.salary_clients = 'yes' THEN 1 ELSE 0 END) AS salary_clients_yes,
            SUM(CASE WHEN a.salary_clients = 'no' THEN 1 ELSE 0 END) AS salary_clients_no,

            -- الإجراء القانوني
            SUM(CASE WHEN a.legal_action = 'يوجد اجراء قانوني' THEN 1 ELSE 0 END) AS legal_yes,
            SUM(CASE WHEN a.legal_action = 'لا يوجد اجراء قانوني' THEN 1 ELSE 0 END) AS legal_no,
            SUM(CASE WHEN a.legal_action = 'غير محدد' THEN 1 ELSE 0 END) AS legal_unknown,

            -- توزيع العقود
            SUM(CASE WHEN a.number_of_contracts = 1 THEN 1 ELSE 0 END) AS single_contracts,
            SUM(CASE WHEN a.number_of_contracts > 1 THEN 1 ELSE 0 END) AS multiple_contracts,
            SUM(a.number_of_contracts) AS total_contracts,

            -- توزيع عمر الدين
            SUM(CASE WHEN STR_TO_DATE(a.date_of_failure, '%Y/%m/%d') BETWEEN '2024-05-07' AND '2025-05-07' THEN 1 ELSE 0 END) AS age_0_1,
            SUM(CASE WHEN STR_TO_DATE(a.date_of_failure, '%Y/%m/%d') BETWEEN '2023-05-08' AND '2024-05-06' THEN 1 ELSE 0 END) AS age_1_2,
            SUM(CASE WHEN STR_TO_DATE(a.date_of_failure, '%Y/%m/%d') BETWEEN '2022-05-08' AND '2023-05-07' THEN 1 ELSE 0 END) AS age_2_3,
            SUM(CASE WHEN STR_TO_DATE(a.date_of_failure, '%Y/%m/%d') BETWEEN '2021-05-08' AND '2022-05-07' THEN 1 ELSE 0 END) AS age_3_4,
            SUM(CASE WHEN STR_TO_DATE(a.date_of_failure, '%Y/%m/%d') BETWEEN '2020-05-08' AND '2021-05-07' THEN 1 ELSE 0 END) AS age_4_5,
            SUM(CASE WHEN STR_TO_DATE(a.date_of_failure, '%Y/%m/%d') < '2020-05-08' THEN 1 ELSE 0 END) AS age_above_5

        FROM 
            attribution6_test a
        LEFT JOIN 
            users u ON u.username = a.n3
        GROUP BY 
            a.product_type, a.n3
        ORDER BY 
            a.product_type, total_clients DESC
    ";

    $query = $this->db->query($sql);
    return $query->result_array();
}

public function get_employees_distribution_report_grouped_by_debt_age()
{
    date_default_timezone_set('Asia/Riyadh');
    $today = date('Y/m/d');

    $age_brackets = [
        ['label' => '0 - 1 سنة', 'start' => date('Y/m/d', strtotime('-1 year +1 day')), 'end' => $today],
        ['label' => '1 - 2 سنة', 'start' => date('Y/m/d', strtotime('-2 year +1 day')), 'end' => date('Y/m/d', strtotime('-1 year'))],
        ['label' => '2 - 3 سنوات', 'start' => date('Y/m/d', strtotime('-3 year +1 day')), 'end' => date('Y/m/d', strtotime('-2 year'))],
        ['label' => '3 - 4 سنوات', 'start' => date('Y/m/d', strtotime('-4 year +1 day')), 'end' => date('Y/m/d', strtotime('-3 year'))],
        ['label' => '4 - 5 سنوات', 'start' => date('Y/m/d', strtotime('-5 year +1 day')), 'end' => date('Y/m/d', strtotime('-4 year'))],
        ['label' => 'أكثر من 5 سنوات', 'start' => null, 'end' => date('Y/m/d', strtotime('-5 year'))],
    ];

    $all_results = [];

    foreach ($age_brackets as $bracket) {
        $label = $bracket['label'];
        $start = $bracket['start'];
        $end = $bracket['end'];

        $where_clause = $start
            ? "a.date_of_failure BETWEEN '{$start}' AND '{$end}'"
            : "a.date_of_failure < '{$end}'";

        $sql = "
            SELECT 
                '{$label}' AS age_category,
                a.product_type,
                a.n3 AS employee_number,
                u.name AS employee_name,
                COUNT(*) AS total_clients,
                SUM(a.h1) AS total_debt,
                SUM(CASE WHEN a.status_com = 'معلوم' THEN 1 ELSE 0 END) AS known_clients,
                SUM(CASE WHEN a.status_com = 'مجهول' THEN 1 ELSE 0 END) AS unknown_clients,

                SUM(CASE WHEN a.h1 < 50000 THEN 1 ELSE 0 END) AS debt_below_50k,
                SUM(CASE WHEN a.h1 >= 50000 AND a.h1 < 100000 THEN 1 ELSE 0 END) AS debt_50k_to_100k,
                SUM(CASE WHEN a.h1 >= 100000 AND a.h1 < 150000 THEN 1 ELSE 0 END) AS debt_100k_to_150k,
                SUM(CASE WHEN a.h1 >= 150000 THEN 1 ELSE 0 END) AS debt_above_150k,

                SUM(CASE WHEN a.id_type = 'هوية مواطن' THEN 1 ELSE 0 END) AS national_saudi,
                SUM(CASE WHEN a.id_type = 'هوية مقيم' THEN 1 ELSE 0 END) AS national_resident,
                SUM(CASE WHEN a.id_type NOT IN ('هوية مواطن', 'هوية مقيم') THEN 1 ELSE 0 END) AS national_others,

                SUM(CASE WHEN a.salary_clients = 'yes' THEN 1 ELSE 0 END) AS salary_clients_yes,
                SUM(CASE WHEN a.salary_clients = 'no' THEN 1 ELSE 0 END) AS salary_clients_no,

                SUM(CASE WHEN a.legal_action = 'يوجد اجراء قانوني' THEN 1 ELSE 0 END) AS legal_yes,
                SUM(CASE WHEN a.legal_action = 'لا يوجد اجراء قانوني' THEN 1 ELSE 0 END) AS legal_no,
                SUM(CASE WHEN a.legal_action = 'غير محدد' THEN 1 ELSE 0 END) AS legal_unknown,

                SUM(CASE WHEN a.number_of_contracts = 1 THEN 1 ELSE 0 END) AS single_contracts,
                SUM(CASE WHEN a.number_of_contracts > 1 THEN 1 ELSE 0 END) AS multiple_contracts,
                SUM(a.number_of_contracts) AS total_contracts,

                -- الفئات العمرية للعملاء
                SUM(CASE 
                    WHEN a.employee_assignment_date IS NULL OR a.employee_assignment_date = '' THEN 1 
                    ELSE 0 
                END) AS age_unknown,

                SUM(CASE 
                    WHEN a.employee_assignment_date IS NOT NULL 
                         AND TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.employee_assignment_date, '%Y/%m/%d'), CURDATE()) < 40 THEN 1 
                    ELSE 0 
                END) AS age_below_40,

                SUM(CASE 
                    WHEN a.employee_assignment_date IS NOT NULL 
                         AND TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.employee_assignment_date, '%Y/%m/%d'), CURDATE()) BETWEEN 40 AND 59 THEN 1 
                    ELSE 0 
                END) AS age_40_to_60,

                SUM(CASE 
                    WHEN a.employee_assignment_date IS NOT NULL 
                         AND TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.employee_assignment_date, '%Y/%m/%d'), CURDATE()) >= 60 THEN 1 
                    ELSE 0 
                END) AS age_above_60

            FROM 
                attribution6_test a
            LEFT JOIN 
                users u ON u.username = a.n3
            WHERE 
                $where_clause
            GROUP BY 
                a.product_type, a.n3
            ORDER BY 
                a.product_type, total_clients DESC
        ";

        $query = $this->db->query($sql);
        $all_results[$label] = $query->result_array();
    }

    return $all_results;
}


