                SUM(CASE WHEN a.h1 >= 50000 AND a.h1 < 100000 THEN a.h1 ELSE 0 END) AS debt_50k_to_100k_amount,

                SUM(CASE WHEN a.h1 >= 100000 AND a.h1 < 150000 THEN 1 ELSE 0 END) AS debt_100k_to_150k,
                SUM(CASE WHEN a.h1 >= 100000 AND a.h1 < 150000 THEN a.h1 ELSE 0 END) AS debt_100k_to_150k_amount,

                SUM(CASE WHEN a.h1 >= 150000 THEN 1 ELSE 0 END) AS debt_above_150k,
                SUM(CASE WHEN a.h1 >= 150000 THEN a.h1 ELSE 0 END) AS debt_above_150k_amount,

                SUM(CASE WHEN a.id_type = 'هوية مواطن' THEN 1 ELSE 0 END) AS national_saudi,
