                SUM(CASE WHEN a.employee_assignment_date IS NOT NULL AND TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.employee_assignment_date, '%Y/%m/%d'), CURDATE()) BETWEEN 40 AND 59 THEN a.h1 ELSE 0 END) AS age_40_to_60_amount,

                SUM(CASE WHEN a.employee_assignment_date IS NOT NULL AND TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.employee_assignment_date, '%Y/%m/%d'), CURDATE()) >= 60 THEN 1 ELSE 0 END) AS age_above_60,
                SUM(CASE WHEN a.employee_assignment_date IS NOT NULL AND TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.employee_assignment_date, '%Y/%m/%d'), CURDATE()) >= 60 THEN a.h1 ELSE 0 END) AS age_above_60_amount

            FROM 
                attribution6_test a
            LEFT JOIN 
                users u ON u.username = a.n3
            WHERE 
                $where_clause
            GROUP BY 
                a.product_type
            ORDER BY 
                a.product_type, total_clients DESC
        ";

        $query = $this->db->query($sql);
        $all_results[$label] = $query->result_array();
    }

    return $all_results;
}


