            SUM(CASE WHEN a.h1 < 50000 THEN 1 ELSE 0 END) AS debt_below_50k,
            SUM(CASE WHEN a.h1 >= 50000 AND a.h1 < 100000 THEN 1 ELSE 0 END) AS debt_50k_to_100k,
            SUM(CASE WHEN a.h1 >= 100000 AND a.h1 < 150000 THEN 1 ELSE 0 END) AS debt_100k_to_150k,
            SUM(CASE WHEN a.h1 >= 150000 THEN 1 ELSE 0 END) AS debt_above_150k,

            -- تقسيم حسب العمر
            SUM(CASE 
                    WHEN a.employee_assignment_date IS NULL OR a.employee_assignment_date = '' 
                    THEN 1 ELSE 0 
                END) AS age_unknown,

            SUM(CASE 
                    WHEN a.employee_assignment_date IS NOT NULL AND 
                         TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.employee_assignment_date, '%Y/%m/%d'), CURDATE()) < 40 
                    THEN 1 ELSE 0 
                END) AS age_below_40,

            SUM(CASE 
                    WHEN a.employee_assignment_date IS NOT NULL AND 
                         TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.employee_assignment_date, '%Y/%m/%d'), CURDATE()) BETWEEN 40 AND 60 
                    THEN 1 ELSE 0 
                END) AS age_40_to_60,

            SUM(CASE 
                    WHEN a.employee_assignment_date IS NOT NULL AND 
                         TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.employee_assignment_date, '%Y/%m/%d'), CURDATE()) > 60 
                    THEN 1 ELSE 0 
                END) AS age_above_60

        FROM 
            attribution6_test a
        LEFT JOIN 
            users u ON u.username = a.n3
        GROUP BY 
            a.customer_category, a.n3
        ORDER BY 
            a.customer_category, total_clients DESC
    ";

    $query = $this->db->query($sql);
    return $query->result_array();
}


