public function get_employee_distribution_report($project_id)
{
    // خريطة جميع جداول attribution
    $attribution_tables = [
        1  => 'attribution',
        5  => 'attribution1',
        55 => 'attribution2',
        4  => 'attribution3',
        3  => 'attribution4',
        33 => 'attribution5',
        6  => 'attribution6',
        7  => 'attribution7',
        2  => 'attribution8',
        8  => 'attribution9',
        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14',
        15 => 'attribution15'
    ];

    if (!isset($attribution_tables[$project_id])) {
        return [];
    }

    $table = $attribution_tables[$project_id];

    $sql = "
        SELECT 
            a.n3 AS employee_number,
            u.name AS employee_name,

            COUNT(*) AS total_clients,
            SUM(a.h1) AS total_debt,

            SUM(CASE WHEN a.status_com = 'معلوم' THEN 1 ELSE 0 END) AS known_clients,
            SUM(CASE WHEN a.status_com = 'مجهول' THEN 1 ELSE 0 END) AS unknown_clients,

            SUM(CASE WHEN a.h1 < 50000 THEN 1 ELSE 0 END) AS debt_below_50k,
            SUM(CASE WHEN a.h1 >= 50000 AND a.h1 < 100000 THEN 1 ELSE 0 END) AS debt_50k_to_100k,
            SUM(CASE WHEN a.h1 >= 100000 AND a.h1 < 150000 THEN 1 ELSE 0 END) AS debt_100k_to_150k,
            SUM(CASE WHEN a.h1 >= 150000 THEN 1 ELSE 0 END) AS debt_above_150k,

            -- أعمار المديونية
            SUM(CASE 
                WHEN TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.n5, '%Y/%m/%d'), CONVERT_TZ(NOW(), '+00:00', '+03:00')) <= 1 
                THEN 1 ELSE 0 END
            ) AS debt_age_1_year_or_less,

            SUM(CASE 
                WHEN TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.n5, '%Y/%m/%d'), CONVERT_TZ(NOW(), '+00:00', '+03:00')) > 1
                     AND TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.n5, '%Y/%m/%d'), CONVERT_TZ(NOW(), '+00:00', '+03:00')) <= 2
                THEN 1 ELSE 0 END
            ) AS debt_age_1_to_2_years,

            SUM(CASE 
                WHEN TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.n5, '%Y/%m/%d'), CONVERT_TZ(NOW(), '+00:00', '+03:00')) > 2
                     AND TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.n5, '%Y/%m/%d'), CONVERT_TZ(NOW(), '+00:00', '+03:00')) <= 3
                THEN 1 ELSE 0 END
            ) AS debt_age_2_to_3_years,

            SUM(CASE 
                WHEN TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.n5, '%Y/%m/%d'), CONVERT_TZ(NOW(), '+00:00', '+03:00')) > 3
                     AND TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.n5, '%Y/%m/%d'), CONVERT_TZ(NOW(), '+00:00', '+03:00')) <= 4
                THEN 1 ELSE 0 END
            ) AS debt_age_3_to_4_years,

            SUM(CASE 
                WHEN TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.n5, '%Y/%m/%d'), CONVERT_TZ(NOW(), '+00:00', '+03:00')) > 4
                     AND TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.n5, '%Y/%m/%d'), CONVERT_TZ(NOW(), '+00:00', '+03:00')) <= 5
                THEN 1 ELSE 0 END
            ) AS debt_age_4_to_5_years,

            SUM(CASE 
                WHEN TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.n5, '%Y/%m/%d'), CONVERT_TZ(NOW(), '+00:00', '+03:00')) > 5
                THEN 1 ELSE 0 END
            ) AS debt_age_above_5_years,

            -- الفئات العمرية للعميل
            SUM(CASE 
                WHEN a.customer_age IS NULL OR a.customer_age = '' 
                THEN 1 ELSE 0 END
            ) AS age_unknown,

            SUM(CASE 
                WHEN a.customer_age IS NOT NULL AND 
                     TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.customer_age, '%Y/%m/%d'), CURDATE()) < 40 
                THEN 1 ELSE 0 END
            ) AS age_below_40,

            SUM(CASE 
                WHEN a.customer_age IS NOT NULL AND 
                     TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.customer_age, '%Y/%m/%d'), CURDATE()) BETWEEN 40 AND 60 
                THEN 1 ELSE 0 END
            ) AS age_40_to_60,

            SUM(CASE 
                WHEN a.customer_age IS NOT NULL AND 
                     TIMESTAMPDIFF(YEAR, STR_TO_DATE(a.customer_age, '%Y/%m/%d'), CURDATE()) > 60 
                THEN 1 ELSE 0 END
            ) AS age_above_60,

            -- العملاء المثبتين
            SUM(CASE WHEN a.stabilizing = 1 THEN 1 ELSE 0 END) AS total_stabilized

        FROM 
            $table a
        LEFT JOIN 
            users u ON u.username = a.n3
        GROUP BY 
            a.n3
        ORDER BY 
            total_clients DESC
    ";

    $query = $this->db->query($sql);
    return $query->result_array();
}




















public function update_product_type_batch()
{
    $sql = "
        UPDATE attribution6_test a
        JOIN (
            SELECT
                t.id,
                CASE
                    WHEN SUM(b.n7 = 2) > 0 THEN 'سيارة'
                    WHEN SUM(b.n7 = 1) > 0 THEN 'قرض'
                    WHEN SUM(b.n7 = 3) > 0 THEN 'فيزا'
                    ELSE NULL
                END AS product_type
            FROM (
                SELECT id, n1 FROM attribution6_test
                WHERE product_type IS NULL OR product_type = ''
                ORDER BY id ASC
                LIMIT 40000
            ) AS t
            LEFT JOIN billfold6_test b ON TRIM(b.n2) = TRIM(t.n1)
            WHERE b.n7 IN (1, 2, 3)
            GROUP BY t.id, t.n1
        ) AS sub ON a.id = sub.id
        SET a.product_type = sub.product_type;
    ";

    return $this->db->query($sql);
}

public function update_date_of_failure_batch()
{
    $sql = "
        UPDATE attribution6_test a
        JOIN (
            SELECT
                t.id,
                MIN(STR_TO_DATE(b.n9, '%Y/%m/%d')) AS failure_date
            FROM (
                SELECT id, n1 FROM attribution6_test
                WHERE date_of_failure IS NULL OR date_of_failure = ''
                ORDER BY id ASC
                LIMIT 40000
            ) AS t
            LEFT JOIN billfold6_test b ON TRIM(b.n2) = TRIM(t.n1)
            WHERE b.n9 IS NOT NULL AND b.n9 != ''
            GROUP BY t.id, t.n1
        ) AS sub ON a.id = sub.id
        SET a.date_of_failure = sub.failure_date;
    ";

    return $this->db->query($sql);
}


public function update_number_of_contracts_batch()
{
    $sql = "
        UPDATE attribution6_test a
        JOIN (
            SELECT
                t.id,
                COUNT(b.n2) AS contracts_count
            FROM (
                SELECT id, n1 FROM attribution6_test
                WHERE number_of_contracts IS NULL OR number_of_contracts = 0
                ORDER BY id ASC
                LIMIT 40000
            ) AS t
            LEFT JOIN billfold6_test b ON TRIM(b.n2) = TRIM(t.n1)
            GROUP BY t.id
        ) AS sub ON a.id = sub.id
        SET a.number_of_contracts = sub.contracts_count;
    ";

    return $this->db->query($sql);
}












public function redistribute_clients_balanced_by_type() {
    // 1. جلب الموظفين من المشروع 6 والنوع 1 فقط
    $employees = $this->db->query("SELECT username FROM users WHERE project = 3 AND type = 1")->result_array();
    if (empty($employees)) {
        echo "لا يوجد موظفين مؤهلين للتوزيع.";
        return;
    }

    $employee_ids = array_column($employees, 'username');

    // تهيئة الأحمال لكل موظف: المديونية، عدد المعلوم، عدد المجهول
    $employee_loads = [];
    foreach ($employee_ids as $id) {
        $employee_loads[$id] = [
            'debt' => 0,
            'ma3loom' => 0,
            'majhool' => 0
        ];
    }

    // 2. جلب العملاء مع معلوماتهم
    $clients = $this->db->query("SELECT id, h1, status_com FROM attribution6_test")->result_array();
    if (empty($clients)) {
        echo "لا يوجد عملاء.";
        return;
    }

    // ترتيب العملاء حسب المديونية من الأعلى للأقل
    usort($clients, function($a, $b) {
        return $b['h1'] <=> $a['h1'];
    });

    // 3. توزيع العملاء بالتوازن (مديونية + معلوم/مجهول)
    foreach ($clients as $client) {
        $type = trim($client['status_com']) == 'معلوم' ? 'ma3loom' : 'majhool';

        // إيجاد الموظف الأنسب من حيث:
        // - الأقل مديونية
        // - والأقل عدد في هذا النوع (معلوم/مجهول)
        $best_employee = null;
        $lowest_score = null;

        foreach ($employee_loads as $emp_id => $load) {
            $score = $load['debt'] + ($load[$type] * 1000); // نعطي أولوية لتوازن النوع، ثم المديونية
            if ($lowest_score === null || $score < $lowest_score) {
                $lowest_score = $score;
                $best_employee = $emp_id;
            }
        }

        // تحديث العميل بالموظف
        $this->db->where('id', $client['id']);
        $this->db->update('attribution6_test', ['n3' => $best_employee]);

        // تحديث الأحمال
        $employee_loads[$best_employee]['debt'] += floatval($client['h1']);
        $employee_loads[$best_employee][$type]++;
    }

   redirect('users/distribution_report');
}

public function redistribute_clients_balanced_by_type101() {
    // 1. جلب الموظفين من المشروع 6 والنوع 1 فقط
    $employees = $this->db->query("SELECT username FROM users WHERE project = 3 AND type = 1")->result_array();
    if (empty($employees)) {
        echo "لا يوجد موظفين مؤهلين للتوزيع.";
        return;
    }

    $employee_ids = array_column($employees, 'username');

    // 2. تهيئة الأحمال لكل موظف: مديونية، معلوم، مجهول، وعدد كل شريحة
    $employee_loads = [];
    foreach ($employee_ids as $id) {
        $employee_loads[$id] = [
            'debt' => 0,
            'ma3loom' => 0,
            'majhool' => 0,
            'below_50k' => 0,
            '50k_100k' => 0,
            '100k_150k' => 0,
            'above_150k' => 0
        ];
    }

    // 3. جلب العملاء مع بيانات المديونية والنوع
    $clients = $this->db->query("SELECT id, h1, status_com FROM attribution6_test")->result_array();
    if (empty($clients)) {
        echo "لا يوجد عملاء.";
        return;
    }

    // ترتيب العملاء حسب المديونية من الأعلى للأقل
    usort($clients, function($a, $b) {
        return $b['h1'] <=> $a['h1'];
    });

    // 4. توزيع العملاء بالتوازن (حسب الشريحة + النوع + المديونية)
    foreach ($clients as $client) {
        $h1 = floatval($client['h1']);
        $status_com = trim($client['status_com']);
        $type = $status_com === 'معلوم' ? 'ma3loom' : 'majhool';

        // تحديد شريحة المديونية
        if ($h1 < 50000) {
            $range = 'below_50k';
        } elseif ($h1 >= 50000 && $h1 < 100000) {
            $range = '50k_100k';
        } elseif ($h1 >= 100000 && $h1 < 150000) {
            $range = '100k_150k';
        } else {
            $range = 'above_150k';
        }

        // إيجاد الموظف الأنسب
        $best_employee = null;
        $lowest_score = null;

        foreach ($employee_loads as $emp_id => $load) {
            // يتم حساب درجة التوازن:
            // عدد العملاء في الشريحة المحددة + عدد نفس النوع + إجمالي المديونية
            $score = $load[$range] * 10000 + $load[$type] * 1000 + $load['debt'];
            if ($lowest_score === null || $score < $lowest_score) {
                $lowest_score = $score;
                $best_employee = $emp_id;
            }
        }

        // تحديث سجل العميل
        $this->db->where('id', $client['id']);
        $this->db->update('attribution6_test', ['n3' => $best_employee]);

        // تحديث الأحمال
        $employee_loads[$best_employee]['debt'] += $h1;
        $employee_loads[$best_employee][$type]++;
        $employee_loads[$best_employee][$range]++;
    }

    // إعادة توجيه للتقرير
    redirect('users/distribution_report102');
}



public function redistribute_clients_balanced_by_type10155112()
{
    // 1. جلب الموظفين من المشروع 3 والنوع 1 مع تصنيف الموظف
    $employees = $this->db->query("SELECT username, employee_classification FROM users WHERE project = 3 AND type = 1")->result_array();
    if (empty($employees)) {
        echo "لا يوجد موظفين مؤهلين للتوزيع.";
        return;
    }

    // 2. تهيئة الأحمال لكل موظف
    $employee_loads = [];
    foreach ($employees as $emp) {
        $employee_loads[$emp['username']] = [
            'classification' => $emp['employee_classification'],
            'debt' => 0,
            'ma3loom' => 0,
            'majhool' => 0,
            'below_50k' => 0,
            '50k_100k' => 0,
            '100k_150k' => 0,
            'above_150k' => 0,
            'below_40' => 0,
            'between_40_60' => 0,
            'above_60' => 0
        ];
    }

    // 3. جلب العملاء مع بيانات التصنيف والعمر
    $clients = $this->db->query("SELECT id, h1, status_com, customer_code, employee_assignment_date FROM attribution6_test")->result_array();
    if (empty($clients)) {
        echo "لا يوجد عملاء.";
        return;
    }

    // ترتيب العملاء حسب المديونية من الأعلى إلى الأقل
    usort($clients, function ($a, $b) {
        return $b['h1'] <=> $a['h1'];
    });

    // 4. توزيع العملاء بالتوازن
    foreach ($clients as $client) {
        $h1 = floatval($client['h1']);
        $status_com = trim($client['status_com']);
        $type = $status_com === 'معلوم' ? 'ma3loom' : 'majhool';
        $customer_code = $client['customer_code'];

        // تحديد شريحة المديونية
        if ($h1 < 50000) {
            $range = 'below_50k';
        } elseif ($h1 >= 50000 && $h1 < 100000) {
            $range = '50k_100k';
        } elseif ($h1 >= 100000 && $h1 < 150000) {
            $range = '100k_150k';
        } else {
            $range = 'above_150k';
        }

        // حساب فئة العمر حسب تاريخ اليوم في الرياض
        date_default_timezone_set('Asia/Riyadh');
        $age_category = null;

        if (!empty($client['employee_assignment_date']) && preg_match('/^\d{4}\/\d{2}\/\d{2}$/', $client['employee_assignment_date'])) {
            try {
                $birth = DateTime::createFromFormat('Y/m/d', $client['employee_assignment_date']);
                $now = new DateTime('now', new DateTimeZone('Asia/Riyadh'));
                $age = $birth->diff($now)->y;

                if ($age < 40) {
                    $age_category = 'below_40';
                } elseif ($age >= 40 && $age <= 60) {
                    $age_category = 'between_40_60';
                } elseif ($age > 60) {
                    $age_category = 'above_60';
                }
            } catch (Exception $e) {
                // تجاهل الحساب في حالة خطأ
            }
        }

        if ($age_category === null) {
            continue; // تجاهل العميل إذا لم يمكن تحديد عمره
        }

        // تصفية الموظفين حسب تطابق التصنيف
        $matching_employees = array_filter($employee_loads, function ($load) use ($customer_code) {
            return $load['classification'] == $customer_code;
        });

        if (empty($matching_employees)) {
            continue; // لا يوجد موظف بنفس التصنيف
        }

        // إيجاد الموظف الأنسب بناءً على العمر + النوع + الشريحة + المديونية
        $best_employee = null;
        $lowest_score = null;

        foreach ($matching_employees as $emp_id => $load) {
            $score = $load[$range] * 1000000 + $load[$type] * 100000 + $load[$age_category] * 10000 + $load['debt'];
            if ($lowest_score === null || $score < $lowest_score) {
                $lowest_score = $score;
                $best_employee = $emp_id;
            }
        }

        // تحديث سجل العميل
        $this->db->where('id', $client['id']);
        $this->db->update('attribution6_test', ['n3' => $best_employee]);

        // تحديث الأحمال
        $employee_loads[$best_employee]['debt'] += $h1;
        $employee_loads[$best_employee][$type]++;
        $employee_loads[$best_employee][$range]++;
        $employee_loads[$best_employee][$age_category]++;
    }

    // إعادة توجيه للتقرير
    redirect('users/distribution_report103');
}


public function redistribute_clients_balanced_by_type1015511255()
{
    // 1. جلب الموظفين من المشروع 3 والنوع 1 مع تصنيف الموظف
    $employees = $this->db->query("SELECT username, employee_classification FROM users WHERE project = 1 AND type = 1")->result_array();
    if (empty($employees)) {
        echo "لا يوجد موظفين مؤهلين للتوزيع.";
        return;
    }

    // 2. تهيئة الأحمال لكل موظف
    $employee_loads = [];
    foreach ($employees as $emp) {
        $employee_loads[$emp['username']] = [
            'classification' => $emp['employee_classification'],
            'debt' => 0,
            'ma3loom' => 0,
            'majhool' => 0,
            'below_50k' => 0,
            '50k_100k' => 0,
            '100k_150k' => 0,
            'above_150k' => 0,
            'below_40' => 0,
            'between_40_60' => 0,
            'above_60' => 0,
            'product_counts' => []  // 🆕 جديد: لتتبع توزيع المنتجات
        ];
    }

    // 3. جلب العملاء مع بيانات التصنيف والعمر والمنتج
    $clients = $this->db->query("SELECT id, h1, status_com, customer_code, employee_assignment_date, product_type FROM attribution6_test")->result_array();
    if (empty($clients)) {
        echo "لا يوجد عملاء.";
        return;
    }

    // ترتيب العملاء حسب المديونية من الأعلى إلى الأقل
    usort($clients, function ($a, $b) {
        return $b['h1'] <=> $a['h1'];
    });

    // 4. توزيع العملاء بالتوازن
    foreach ($clients as $client) {
        $h1 = floatval($client['h1']);
        $status_com = trim($client['status_com']);
        $type = $status_com === 'معلوم' ? 'ma3loom' : 'majhool';
        $customer_code = $client['customer_code'];
        $product_type = trim($client['product_type']);

        // تحديد شريحة المديونية
        if ($h1 < 50000) {
            $range = 'below_50k';
        } elseif ($h1 >= 50000 && $h1 < 100000) {
            $range = '50k_100k';
        } elseif ($h1 >= 100000 && $h1 < 150000) {
            $range = '100k_150k';
        } else {
            $range = 'above_150k';
        }

        // حساب فئة العمر
        date_default_timezone_set('Asia/Riyadh');
        $age_category = null;
        if (!empty($client['employee_assignment_date']) && preg_match('/^\d{4}\/\d{2}\/\d{2}$/', $client['employee_assignment_date'])) {
            try {
                $birth = DateTime::createFromFormat('Y/m/d', $client['employee_assignment_date']);
                $now = new DateTime('now', new DateTimeZone('Asia/Riyadh'));
                $age = $birth->diff($now)->y;

                if ($age < 40) {
                    $age_category = 'below_40';
                } elseif ($age >= 40 && $age <= 60) {
                    $age_category = 'between_40_60';
                } elseif ($age > 60) {
                    $age_category = 'above_60';
                }
            } catch (Exception $e) {
                // تجاهل الحساب في حالة خطأ
            }
        }

        if ($age_category === null) {
            continue; // تجاهل العميل إذا لم يمكن تحديد عمره
        }

        // تصفية الموظفين حسب تطابق التصنيف
        $matching_employees = array_filter($employee_loads, function ($load) use ($customer_code) {
            return $load['classification'] == $customer_code;
        });

        if (empty($matching_employees)) {
            continue; // لا يوجد موظف بنفس التصنيف
        }

        // إيجاد الموظف الأنسب بناءً على الأحمال والمنتجات
        $best_employee = null;
        $lowest_score = null;

        foreach ($matching_employees as $emp_id => $load) {
            $product_count = isset($load['product_counts'][$product_type]) ? $load['product_counts'][$product_type] : 0;
            $score = $product_count * 10000000 + $load[$range] * 1000000 + $load[$type] * 100000 + $load[$age_category] * 10000 + $load['debt'];
            if ($lowest_score === null || $score < $lowest_score) {
                $lowest_score = $score;
                $best_employee = $emp_id;
            }
        }

        // تحديث سجل العميل
        $this->db->where('id', $client['id']);
        $this->db->update('attribution6_test', ['n3' => $best_employee]);

        // تحديث الأحمال
        $employee_loads[$best_employee]['debt'] += $h1;
        $employee_loads[$best_employee][$type]++;
        $employee_loads[$best_employee][$range]++;
        $employee_loads[$best_employee][$age_category]++;
        if (!isset($employee_loads[$best_employee]['product_counts'][$product_type])) {
            $employee_loads[$best_employee]['product_counts'][$product_type] = 0;
        }
        $employee_loads[$best_employee]['product_counts'][$product_type]++;
    }

    // إعادة توجيه للتقرير
    redirect('users/distribution_report103');
}





