public function export_excel($billfold) {
    // تحميل المكتبة
    require_once(APPPATH.'third_party/vendor/autoload.php');

    $spreadsheet = new \PhpOffice\PhpSpreadsheet\Spreadsheet();
    $sheet = $spreadsheet->getActiveSheet();

    // جلب البيانات
    $query = $this->db->query("SELECT * FROM $billfold");
    $rows = $query->result_array();

    if (empty($rows)) {
        show_error("لا توجد بيانات للتصدير.");
    }

    // عناوين الأعمدة
    $col = 1;
    foreach (array_keys($rows[0]) as $field) {
        $sheet->setCellValueByColumnAndRow($col++, 1, $field);
    }

    // البيانات
    $row_num = 2;
    foreach ($rows as $row) {
        $col = 1;
        foreach ($row as $value) {
            $sheet->setCellValueExplicitByColumnAndRow($col++, $row_num, $value, \PhpOffice\PhpSpreadsheet\Cell\DataType::TYPE_STRING);
        }
        $row_num++;
    }

    // إنشاء الملف
    $writer = new \PhpOffice\PhpSpreadsheet\Writer\Xlsx($spreadsheet);
    $filename = "billfold_export.xlsx";

    // إرسال للتحميل
    header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
    header("Content-Disposition: attachment;filename=\"$filename\"");
    header('Cache-Control: max-age=0');
    $writer->save('php://output');
    exit;
}



