    function createcsv_text_format($attribution){
    $this->load->dbutil();
    $this->load->helper('file');
    $this->load->helper('download');

    $query = $this->db->query("SELECT * FROM $attribution");
    $rows = $query->result_array();

    $output = "";

    if (!empty($rows)) {
        // إضافة العناوين
        $headers = array_keys($rows[0]);
        $output .= implode(",", $headers) . "\r\n";

        foreach ($rows as $row) {
            $line = [];
            foreach ($row as $value) {
                // صيغة النص لملف Excel
                $line[] = '="' . str_replace('"', '""', $value) . '"';
            }
            $output .= implode(",", $line) . "\r\n";
        }
    }

    $filename = "attribution.csv";
    force_download($filename, "\xEF\xBB\xBF" . $output);
}


