  public function get_data_by_date_range($start_date, $end_date) {
    $this->db->select('*'); // حدد الأعمدة المطلوبة
    $this->db->from('employee_follow_up'); // اسم الجدول المطلوب
    
    // شروط التواريخ
    $this->db->where('n4 >=', $start_date); // شرط تاريخ البداية
    $this->db->where('n4 <=', $end_date); // شرط تاريخ النهاية

    

    // تنفيذ الاستعلام
    $query = $this->db->get();

    return $query->result_array(); // إرجاع النتائج كمصفوفة
}


