public function get_billfold155999202052154125($start_date, $end_date, $f) {
    $this->db->select('a.h4, 
        SUM(CASE WHEN b.com_status = "معلوم" THEN 1 ELSE 0 END) AS known_count,
        SUM(CASE WHEN b.com_status = "مجهول" THEN 1 ELSE 0 END) AS unknown_count,
        COUNT(b.n2) AS total_n2_count'); // احتساب العدد الإجمالي لـ n2 بدون إلغاء التكرار

    $this->db->from("$f AS b"); // تعيين alias للجدول الأساسي

    // الربط مع جدول attribution على أساس أن n1 من attribution = n2 من billfold
    $this->db->join('attribution AS a', 'a.n1 = b.n2', 'inner');

    // شروط التواريخ من الجدول billfold
    $this->db->where('b.k10 >=', $start_date); // شرط تاريخ البداية
    $this->db->where('b.k10 <=', $end_date); // شرط تاريخ النهاية

    // تجميع النتائج حسب h4
    $this->db->group_by('a.h4'); 

    // تنفيذ الاستعلام
    $query = $this->db->get();

    return $query->result_array(); // إرجاع النتائج كمصفوفة
}

public function get_billfold1559992020521541251($f) {
    $this->db->select('a.h4, 
        SUM(CASE WHEN b.com_status = "معلوم" THEN 1 ELSE 0 END) AS known_count,
        SUM(CASE WHEN b.com_status = "مجهول" THEN 1 ELSE 0 END) AS unknown_count,
        COUNT(DISTINCT b.n2) AS total_n2_count'); // احتساب العدد الفريد لـ n2 بدون التكرار

    $this->db->from("$f AS b"); // تعيين alias للجدول الأساسي

    // الربط مع جدول attribution على أساس أن n1 من attribution = n2 من billfold
    $this->db->join('attribution AS a', 'a.n1 = b.n2', 'inner');

    // إضافة شرط للتأكد من أن n1 = n2
    $this->db->where('a.n1 = b.n2');

    // تجميع النتائج حسب h4
    $this->db->group_by('a.h4'); 

    // تنفيذ الاستعلام
    $query = $this->db->get();

    return $query->result_array(); // إرجاع النتائج كمصفوفة
}
public function get_supervisors_client_count() {
    $this->db->select('
        a.h4 AS supervisor, 
        COUNT(DISTINCT a.n1) AS client_count,
        COUNT(DISTINCT b.n2) AS unique_n2_count,
        SUM(CASE WHEN b.com_status = "معلوم" THEN 1 ELSE 0 END) AS known_count,
        SUM(CASE WHEN b.com_status = "مجهول" THEN 1 ELSE 0 END) AS unknown_count
    ');

    $this->db->from('attribution AS a'); // الجدول الأساسي attribution

    // الربط مع جدول billfold بحيث يكون n1 من attribution = n2 من billfold
    $this->db->join('billfold AS b', 'a.n1 = b.n2', 'inner');

    // تجميع النتائج حسب المشرف h4
    $this->db->group_by('a.h4'); 

    // تنفيذ الاستعلام
    $query = $this->db->get();

    return $query->result_array(); // إرجاع النتائج كمصفوفة
}

 public function get_supervisors_client_summary() {
    $this->db->select('
        h4 AS supervisor, 
        COUNT(DISTINCT n1) AS client_count,

        -- عدد العملاء "معلوم"
        SUM(CASE WHEN status_com = "معلوم" THEN 1 ELSE 0 END) AS known_count,

        -- عدد الموظفين "معلوم"
        SUM(CASE WHEN status_emp = "معلوم" THEN 1 ELSE 0 END) AS known_count1,

        -- عدد العملاء "مجهول"
        SUM(CASE WHEN status_com = "مجهول" THEN 1 ELSE 0 END) AS unknown_count,

        -- عدد الموظفين "مجهول"
        SUM(CASE WHEN status_emp = "مجهول" THEN 1 ELSE 0 END) AS unknown_count1,

        -- نسبة العملاء "معلوم" من إجمالي العملاء
        (SUM(CASE WHEN status_com = "معلوم" THEN 1 ELSE 0 END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS known_percentage,

        -- نسبة العملاء "مجهول" من إجمالي العملاء
        (SUM(CASE WHEN status_com = "مجهول" THEN 1 ELSE 0 END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS unknown_percentage,

        -- نسبة الموظفين "معلوم" من إجمالي العملاء
        (SUM(CASE WHEN status_emp = "معلوم" THEN 1 ELSE 0 END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS known_percentage1,

        -- نسبة الموظفين "مجهول" من إجمالي العملاء
        (SUM(CASE WHEN status_emp = "مجهول" THEN 1 ELSE 0 END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS unknown_percentage1,

        -- عدد الموظفين "معلوم" للعمود الجديد status_emp1
        SUM(CASE WHEN status_emp1 = "معلوم" THEN 1 ELSE 0 END) AS known_count_emp1,

        -- عدد الموظفين "مجهول" للعمود الجديد status_emp1
        SUM(CASE WHEN status_emp1 = "مجهول" THEN 1 ELSE 0 END) AS unknown_count_emp1,

        -- نسبة الموظفين "معلوم" للعمود الجديد status_emp1 من إجمالي العملاء
        (SUM(CASE WHEN status_emp1 = "معلوم" THEN 1 ELSE 0 END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS known_percentage_emp1,

        -- نسبة الموظفين "مجهول" للعمود الجديد status_emp1 من إجمالي العملاء
        (SUM(CASE WHEN status_emp1 = "مجهول" THEN 1 ELSE 0 END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS unknown_percentage_emp1,

        -- عدد الموظفين حسب تصنيفات أخرى للعمود emp_det1
        SUM(CASE WHEN emp_det1 = "تفصيل1" THEN 1 ELSE 0 END) AS emp_det1_count1,
        SUM(CASE WHEN emp_det1 = "تفصيل2" THEN 1 ELSE 0 END) AS emp_det1_count2
    ');

    $this->db->from('attribution'); // تحديد الجدول

    // استبعاد المشرفين الذين ليس لديهم اسم (h4 فارغ)
    $this->db->where('h4 !=', ''); 

    // تجميع النتائج حسب المشرف h4
    $this->db->group_by('h4'); 

    // ترتيب النتائج تنازليًا حسب نسبة "معلوم"
    $this->db->order_by('known_percentage', 'DESC');

    // تنفيذ الاستعلام
    $query = $this->db->get();

    return $query->result_array(); // إرجاع النتائج كمصفوفة
}

