public function get_confirmed_reimbursements_details()
{
    $sql = "
        SELECT 
            pl.name AS project_name,
            er.x3 AS supervisor_id,
            u.name AS supervisor_name,
            SUM(er.n2) AS total_confirmed
        FROM 
            employee_reimbursements er
        JOIN 
            projects_list pl ON er.project_id = pl.code
        LEFT JOIN 
            users u ON er.x3 = u.username
        WHERE 
            er.status = 1
            AND DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m') = DATE_FORMAT(CURDATE(), '%Y-%m')
        GROUP BY 
            pl.name, er.x3, u.name
        ORDER BY 
            pl.name, er.x3
    ";

    $query = $this->db->query($sql);
    return $query->result_array();
}


public function get_project_supervisor_comparison()
{
    $sql = "
        SELECT 
            pl.name AS project_name,
            er.project_id,
            u.name AS supervisor_name,
            er.x3 AS supervisor_id,
            DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m') AS month,
            DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m-%d') AS full_date,
            SUM(er.n2) AS total_confirmed
        FROM 
            employee_reimbursements er
        JOIN 
            projects_list pl ON er.project_id = pl.code
        LEFT JOIN 
            users u ON u.username = er.x3
        WHERE 
            er.status = 1
            AND (
                DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m') IN (
                    DATE_FORMAT(CURDATE(), '%Y-%m'),
                    DATE_FORMAT(CURDATE() - INTERVAL 1 MONTH, '%Y-%m')
                )
                OR DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m-%d') = CURDATE()
            )
        GROUP BY 
            er.project_id, er.x3, month, full_date
        ORDER BY 
            pl.name, er.x3, month
    ";

    return $this->db->query($sql)->result_array();
}


 public function get_project_supervisor_comparison11()
{
    $sql = "
        SELECT 
            pl.name AS project_name,
            er.project_id,
            u.name AS supervisor_name,
            er.x3 AS supervisor_id,
            DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m') AS month,
            DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m-%d') AS full_date,
            SUM(er.n2) AS total_confirmed
        FROM 
            employee_reimbursements er
        JOIN 
            projects_list pl ON er.project_id = pl.code
        LEFT JOIN 
            users u ON u.username = er.x3
        WHERE 
            er.status = 1
            AND (
                -- الشهر الحالي حتى اليوم
                STR_TO_DATE(er.n8, '%Y/%m/%d') BETWEEN DATE_FORMAT(CURDATE(), '%Y-%m-01') AND CURDATE()

                OR

                -- الشهر الماضي حتى نفس اليوم
                STR_TO_DATE(er.n8, '%Y/%m/%d') BETWEEN 
                    DATE_FORMAT(CURDATE() - INTERVAL 1 MONTH, '%Y-%m-01')
                    AND LAST_DAY(CURDATE() - INTERVAL 1 MONTH) - INTERVAL (DAY(CURDATE()) - 1) DAY

                OR

                -- الشهر الماضي كاملًا
                STR_TO_DATE(er.n8, '%Y/%m/%d') BETWEEN 
                    DATE_FORMAT(CURDATE() - INTERVAL 1 MONTH, '%Y-%m-01')
                    AND LAST_DAY(CURDATE() - INTERVAL 1 MONTH)
            )
        GROUP BY 
            er.project_id, er.x3, month, full_date
        ORDER BY 
            pl.name, er.x3, month
    ";

    return $this->db->query($sql)->result_array();
}

 public function get_project_supervisor_comparison111()
{
    $sql = "
        SELECT 
            pl.name AS project_name,
            er.project_id,
            u.name AS supervisor_name,
            er.x3 AS supervisor_id,
            DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m') AS month,
            DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m-%d') AS full_date,
            SUM(er.n2) AS total_confirmed,

            -- ✅ محفظة المشروع حسب تاريخ الإسناد بصيغة yyyy/mm
            (
                SELECT a.n3 
                FROM attribution_all a 
                WHERE 
                    a.n1 = er.project_id 
                    AND DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y/%m') = a.n4
                LIMIT 1
            ) AS total_portfolio

        FROM 
            employee_reimbursements er
        JOIN 
            projects_list pl ON er.project_id = pl.code
        LEFT JOIN 
            users u ON u.username = er.x3
        WHERE 
            er.status = 1
            AND (
                -- الشهر الحالي حتى اليوم
                STR_TO_DATE(er.n8, '%Y/%m/%d') BETWEEN DATE_FORMAT(CURDATE(), '%Y-%m-01') AND CURDATE()

                OR

                -- الشهر الماضي حتى نفس اليوم
                STR_TO_DATE(er.n8, '%Y/%m/%d') BETWEEN 
                    DATE_FORMAT(CURDATE() - INTERVAL 1 MONTH, '%Y-%m-01')
                    AND LAST_DAY(CURDATE() - INTERVAL 1 MONTH) - INTERVAL (DAY(CURDATE()) - 1) DAY

                OR

                -- الشهر الماضي كاملًا
                STR_TO_DATE(er.n8, '%Y/%m/%d') BETWEEN 
                    DATE_FORMAT(CURDATE() - INTERVAL 1 MONTH, '%Y-%m-01')
                    AND LAST_DAY(CURDATE() - INTERVAL 1 MONTH)
            )
        GROUP BY 
            er.project_id, er.x3, month, full_date
        ORDER BY 
            pl.name, er.x3, month
    ";

    return $this->db->query($sql)->result_array();
}


public function get_project_supervisor_comparison1111()
{
    $sql = "
        SELECT 
            pl.name AS project_name,
            er.project_id,
            u.name AS supervisor_name,
            er.x3 AS supervisor_id,
            DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m') AS month,
            DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m-%d') AS full_date,
            SUM(er.n2) AS total_confirmed,

            -- ✅ محفظة المشروع حسب تاريخ الإسناد بصيغة yyyy/mm
            (
                SELECT a.n3 
                FROM attribution_all a 
                WHERE 
                    a.n1 = er.project_id 
                    AND DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y/%m') = a.n4
                LIMIT 1
            ) AS total_portfolio,

            -- ✅ إجمالي المستهدف من جدول traget_report حسب المشروع والشهر الحالي
            (
                SELECT SUM(t.n8)
                FROM traget_report t
                WHERE 
                    t.n5 = er.project_id 
                    AND DATE_FORMAT(STR_TO_DATE(t.date, '%Y/%m'), '%Y-%m') = DATE_FORMAT(CURDATE(), '%Y-%m')
            ) AS total_target_current

        FROM 
            employee_reimbursements er
        JOIN 
            projects_list pl ON er.project_id = pl.code
        LEFT JOIN 
            users u ON u.username = er.x3
        WHERE 
            er.status = 1
            AND (
                -- الشهر الحالي حتى اليوم
                STR_TO_DATE(er.n8, '%Y/%m/%d') BETWEEN DATE_FORMAT(CURDATE(), '%Y-%m-01') AND CURDATE()

                OR

                -- الشهر الماضي حتى نفس اليوم
                STR_TO_DATE(er.n8, '%Y/%m/%d') BETWEEN 
                    DATE_FORMAT(CURDATE() - INTERVAL 1 MONTH, '%Y-%m-01')
                    AND LAST_DAY(CURDATE() - INTERVAL 1 MONTH) - INTERVAL (DAY(CURDATE()) - 1) DAY

                OR

                -- الشهر الماضي كاملًا
                STR_TO_DATE(er.n8, '%Y/%m/%d') BETWEEN 
                    DATE_FORMAT(CURDATE() - INTERVAL 1 MONTH, '%Y-%m-01')
                    AND LAST_DAY(CURDATE() - INTERVAL 1 MONTH)
            )
        GROUP BY 
            er.project_id, er.x3, month, full_date
        ORDER BY 
            pl.name, er.x3, month
    ";

    return $this->db->query($sql)->result_array();
}

