                    AND DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y/%m') = a.n4
                    LIMIT 1
                ) AS total_portfolio,

                (
                    SELECT SUM(t.n8)
                    FROM traget_report t
                    WHERE t.n5 = er.project_id 
                    AND DATE_FORMAT(t.date, '%Y-%m') = ?
                ) AS total_target_current

            FROM employee_reimbursements er
            JOIN projects_list pl ON er.project_id = pl.code
            LEFT JOIN users u ON u.username = er.x3
            WHERE er.status = 1
                AND DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m') = ?
