public function get_project_supervisor_comparison_previous_month111()
{
    $sql = "
        SELECT 
            pl.name AS project_name,
            er.project_id,
            u.name AS supervisor_name,
            er.x3 AS supervisor_id,
            DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m') AS month,
            DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y-%m-%d') AS full_date,
            SUM(er.n2) AS total_confirmed,

            -- ✅ محفظة المشروع حسب تاريخ الإسناد بصيغة yyyy/mm
            (
                SELECT a.n3 
                FROM attribution_all a 
                WHERE 
                    a.n1 = er.project_id 
                    AND DATE_FORMAT(STR_TO_DATE(er.n8, '%Y/%m/%d'), '%Y/%m') = a.n4
                LIMIT 1
            ) AS total_portfolio,

            -- ✅ إجمالي المستهدف من جدول traget_report حسب المشروع والشهر السابق
            (
                SELECT SUM(t.n8)
                FROM traget_report t
                WHERE 
                    t.n5 = er.project_id 
                    AND DATE_FORMAT(STR_TO_DATE(t.date, '%Y/%m'), '%Y-%m') = DATE_FORMAT(CURDATE() - INTERVAL 1 MONTH, '%Y-%m')
            ) AS total_target_previous

        FROM 
            employee_reimbursements er
        JOIN 
            projects_list pl ON er.project_id = pl.code
        LEFT JOIN 
            users u ON u.username = er.x3
        WHERE 
            er.status = 1
            AND (
                -- بيانات الشهر السابق فقط (كامل الشهر)
                STR_TO_DATE(er.n8, '%Y/%m/%d') BETWEEN 
                    DATE_FORMAT(CURDATE() - INTERVAL 1 MONTH, '%Y-%m-01')
                    AND LAST_DAY(CURDATE() - INTERVAL 1 MONTH)
            )
        GROUP BY 
            er.project_id, er.x3, month, full_date
        ORDER BY 
            pl.name, er.x3, month
    ";

    return $this->db->query($sql)->result_array();
}

 






public function get_project_supervisor_comparison_1($month1, $month2)
{
    $sql = "
        SELECT 
            pl.name AS project_name,
            er.project_id,
            u.name AS supervisor_name,
            er.x3 AS supervisor_id,
            LEFT(er.n8, 7) AS month, -- نأخذ yyyy/mm فقط
            er.n8 AS full_date,
            SUM(er.n2) AS total_confirmed
        FROM 
            employee_reimbursements er
        JOIN 
            projects_list pl ON er.project_id = pl.code
        LEFT JOIN 
            users u ON u.username = er.x3
        WHERE 
            er.status = 1
            AND LEFT(er.n8, 7) IN (?, ?)
        GROUP BY 
            er.project_id, er.x3, month, full_date
        ORDER BY 
            pl.name, er.x3, month
    ";

    return $this->db->query($sql, [$month1, $month2])->result_array();
}













public function get_supervisor_employees_summary252($id2,$attribution) {
    $this->db->select('
        n3 AS employee,
        COUNT(DISTINCT n1) AS client_count,

        -- عدد العملاء "معلوم"
        SUM(CASE WHEN status_com = "معلوم" THEN 1 ELSE 0 END) AS known_count,

        -- عدد العملاء "مجهول"
        SUM(CASE WHEN status_com = "مجهول" THEN 1 ELSE 0 END) AS unknown_count,

        -- عدد الموظفين "معلوم"
        COUNT(CASE WHEN status_emp = "معلوم" THEN n3 ELSE NULL END) AS known_emp_count,

        -- عدد الموظفين "مجهول"
        COUNT(CASE WHEN status_emp = "مجهول" THEN n3 ELSE NULL END) AS unknown_emp_count,

        -- عدد الموظفين "معلوم" للعمود الجديد status_emp1
        COUNT(CASE WHEN status_emp1 = "معلوم" THEN n3 ELSE NULL END) AS known_emp1_count,

        -- عدد الموظفين "مجهول" للعمود الجديد status_emp1
        COUNT(CASE WHEN status_emp1 = "مجهول" THEN n3 ELSE NULL END) AS unknown_emp1_count,

        -- نسبة العملاء "معلوم" من إجمالي العملاء لكل موظف
        (SUM(CASE WHEN status_com = "معلوم" THEN 1 ELSE 0 END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS known_percentage,

        -- نسبة العملاء "مجهول" من إجمالي العملاء لكل موظف
        (SUM(CASE WHEN status_com = "مجهول" THEN 1 ELSE 0 END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS unknown_percentage,

        -- نسبة الموظفين "معلوم" من إجمالي الموظفين لكل موظف
        (COUNT(CASE WHEN status_emp = "معلوم" THEN n1 ELSE NULL END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS known_emp_percentage,

        -- نسبة الموظفين "مجهول" من إجمالي الموظفين لكل موظف
        (COUNT(CASE WHEN status_emp = "مجهول" THEN n1 ELSE NULL END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS unknown_emp_percentage,

        -- نسبة الموظفين "معلوم" للعمود الجديد status_emp1
        (COUNT(CASE WHEN status_emp1 = "معلوم" THEN n1 ELSE NULL END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS known_emp1_percentage,

        -- نسبة الموظفين "مجهول" للعمود الجديد status_emp1
        (COUNT(CASE WHEN status_emp1 = "مجهول" THEN n1 ELSE NULL END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS unknown_emp1_percentage
    ');

    $this->db->from($attribution); // تحديد الجدول

    // تصفية التقرير بناءً على المشرف المحدد ($id2)
    $this->db->where('h4', $id2); 

    // استبعاد الصفوف التي لا تحتوي على اسم الموظف
    $this->db->where('n3 !=', ''); 

    // تجميع النتائج حسب الموظف n3 فقط
    $this->db->group_by('n3'); 

    // ترتيب النتائج تنازليًا حسب نسبة "معلوم" للموظفين
    $this->db->order_by('known_emp_percentage', 'DESC');

    // تنفيذ الاستعلام
    $query = $this->db->get();

    return $query->result_array(); // إرجاع النتائج كمصفوفة
}


