        (SUM(CASE WHEN status_com = "مجهول" THEN 1 ELSE 0 END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS unknown_percentage,

        -- نسبة الموظفين "معلوم"
        (COUNT(CASE WHEN status_emp = "معلوم" THEN n1 ELSE NULL END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS known_emp_percentage,

        -- نسبة الموظفين "مجهول"
        (COUNT(CASE WHEN status_emp = "مجهول" THEN n1 ELSE NULL END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS unknown_emp_percentage,

        -- نسبة الموظفين "معلوم" لـ status_emp1
        (COUNT(CASE WHEN status_emp1 = "معلوم" THEN n1 ELSE NULL END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS known_emp1_percentage,

        -- نسبة الموظفين "مجهول" لـ status_emp1
        (COUNT(CASE WHEN status_emp1 = "مجهول" THEN n1 ELSE NULL END) / NULLIF(COUNT(DISTINCT n1), 0)) * 100 AS unknown_emp1_percentage,

        -- ✅ متوسط عدد العملاء لكل موظف (بما أن التجميع حسب الموظف فالقيمة = عدد العملاء فعليًا)
        COUNT(DISTINCT n1) AS avg_clients_per_employee,

        -- ✅ إجمالي مبلغ المديونية لكل موظف (جمع h1)
        SUM(CASE WHEN h1 REGEXP "^-?[0-9]+(\.[0-9]+)?$" THEN CAST(h1 AS DECIMAL(15,2)) ELSE 0 END) AS total_debt
    ');

    $this->db->from($attribution);

    $this->db->where('h4', $id2);
    $this->db->where('n3 !=', '');
    $this->db->group_by('n3');
    $this->db->order_by('known_emp_percentage', 'DESC');

    $query = $this->db->get();
    return $query->result_array();
}




