    $username = $this->session->userdata('username');

    $this->db->select('*');
    $this->db->from('employee_reimbursements');

    // شروط التواريخ
    $this->db->where('n8 >=', $start_date);
    $this->db->where('n8 <=', $end_date);

    // شرط (x3 أو n6 يساوي اسم المستخدم)
    $this->db->group_start(); // ← تبدأ مجموعة OR
        $this->db->where('x3', $username);
        $this->db->or_where('n6', $username);
    $this->db->group_end(); // ← تنتهي مجموعة OR

    // السدادات المؤكدة
    $this->db->where('status', 1);

    // تنفيذ الاستعلام
    $query = $this->db->get();

    return $query->result_array();
}





