function createcsv555masterattribution6_test521474585585212141111qqqq1(){
    $this->load->dbutil();
    $this->load->helper('file');
    $this->load->helper('download');
    $delimiter = ",";
    $newline = "\r\n";
    $filename = "clients_not_in_new1.csv";

    // استخدام LEFT JOIN لأداء أسرع
    $query = "
        SELECT o.*
        FROM old1 o
        LEFT JOIN new1 n ON o.CONTRACT_All = n.CONTRACT_All
        WHERE n.CONTRACT_All IS NULL
    ";

    $result = $this->db->query($query);

    // إنشاء CSV
    $data = $this->dbutil->csv_from_result($result, $delimiter, $newline);

    // إضافة BOM لدعم اللغة العربية
    force_download($filename, "\xEF\xBB\xBF" . $data);
}

function createcsv555masterattribution6_test52147458558521214111www11(){
    $this->load->dbutil();
