    $delimiter = ",";
    $newline = "\r\n";
    $filename = "clients_not_in_new1.csv";

    // LEFT JOIN مع شرط Employee_Name
    $query = "
        SELECT o.*
        FROM old1 o
        LEFT JOIN new1 n ON o.CONTRACT_All = n.CONTRACT_All
        WHERE n.CONTRACT_All IS NULL
          AND o.Employee_Name = 'MARSOOM'
    ";

    $result = $this->db->query($query);

