        //Related_add
        function related_add($did,$uid,$name,$phone,$mail,$job,$address)
        {
            if($name !== null)
            {
                $data = array(
                    'did' => $did,
                    'uid' => $uid,
                    'name' => $name,
                    'mobile' => $phone,
                    'email' => $mail,
                    'transaction' => $address,
                    'office' => $job
                
                );
                $this->db->insert('relatedpeople', $data);
            }
        }
