      function get_operation_orders12515254125($id, $id2) {
    // ربط قيم n10 بأسماء الجداول
    $tables = [
        1  => 'attribution',
        5  => 'attribution1',
        55 => 'attribution2',
        4  => 'attribution3',
        3  => 'attribution4',
        33 => 'attribution5',
        6  => 'attribution6',
        7  => 'attribution7',
        2  => 'attribution8',
        8  => 'attribution9',
        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14'
    ];

    // تحقق هل n10 موجود في المصفوفة
    if (array_key_exists($id, $tables)) {
        $tableName = $tables[$id];

        // LEFT JOIN لعرض العملاء الغير مسندين (NULL)
        $sql = "
            SELECT o.*
            FROM operation_orders o
            LEFT JOIN $tableName a ON o.n2 = a.n1
            WHERE o.status = $id2 AND o.n10 = $id AND a.n1 IS NULL
            ORDER BY o.id DESC;
        ";
    } else {
        // لو n10 غير موجود بالقائمة نرجع الكويري العادي (كلهم غير مسندين تلقائيًا)
        $sql = "
            SELECT *
            FROM operation_orders
            WHERE status = $id2 AND n10 = $id
            ORDER BY id DESC;
        ";
    }

    $query = $this->db->query($sql);
    return $query->result_array();
}


