        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14'
    ];

    // تحقق هل n10 موجود في المصفوفة
    if (array_key_exists($id, $tables)) {
        $tableName = $tables[$id];

        // JOIN لجلب العملاء المسندين فقط
        $sql = "
            SELECT o.*
            FROM operation_orders o
            INNER JOIN $tableName a ON o.n2 = a.n1
            WHERE o.status = $id2 AND o.n10 = $id
            ORDER BY o.id DESC;
        ";
    } else {
        // في حال n10 غير موجود في القائمة نرجع الكويري العادي
