      function get_attribution2225214() {
    $id = $this->session->userdata('username');
    $current_month = date('Y/m'); // yyyy/mm

    $sql = "
        SELECT a.n1, a.h1, a.h2, a.h3, a.status
        FROM $this->attribution a
        LEFT JOIN (
            SELECT x1
            FROM employee_follow_up
            WHERE DATE_FORMAT(n4, '%Y/%m') = ?
            GROUP BY x1
        ) f ON a.n1 = f.x1
        WHERE a.n3 = ?
        AND f.x1 IS NULL
    ";

    $query = $this->db->query($sql, [$current_month, $id]);
    return $query->result_array();
}

 function get_attribution222521455() {
    $id = $this->session->userdata('username'); // رقم الموظف الحالي
    $current_month = date('Y/m'); // yyyy/mm

    $sql = "
        SELECT a.n1, a.h1, a.h2, a.h3, a.status
        FROM $this->attribution a
        LEFT JOIN (
            SELECT x1
            FROM employee_follow_up
            WHERE DATE_FORMAT(n4, '%Y/%m') = ?
            AND x3 = ?
            GROUP BY x1
        ) f ON a.n1 = f.x1
        WHERE a.h4 = ?
        AND f.x1 IS NULL
    ";

    $query = $this->db->query($sql, [$current_month, $id, $id]);
    return $query->result_array();
}

function get_attribution22252145511() {
    $project = $this->session->userdata('project'); // كود المشروع الحالي
    $current_month = date('Y/m'); // yyyy/mm

    $sql = "
        SELECT a.n1, a.h1, a.h2, a.h3, a.status
        FROM $this->attribution a
        LEFT JOIN (
            SELECT x1
            FROM employee_follow_up
            WHERE DATE_FORMAT(n4, '%Y/%m') = ?
            AND project = ?
            GROUP BY x1
        ) f ON a.n1 = f.x1
        WHERE a.project_id = ?
        AND f.x1 IS NULL
    ";

    $query = $this->db->query($sql, [$current_month, $project, $project]);
    return $query->result_array();
}



      public function check_full_payment($customer_id, $total_debt) {
    $this->db->select_sum('n2');
    $this->db->from('employee_reimbursements');
    $this->db->where('x1', $customer_id);
    $this->db->where('status', '1'); // ✅ السدادات المؤكدة فقط

    $query = $this->db->get();
    $result = $query->row();

    $total_paid = $result ? (float)$result->n2 : 0;

    if ($total_paid >= $total_debt) {
        return 1; // ✅ تم السداد بالكامل أو أكثر
    } else {
        return 0; // ❌ لا يزال هناك مديونية
    }
}


