function get_employee_notebook() {
    // تحديد المنطقة الزمنية
    date_default_timezone_set('Asia/Riyadh');

    // تحديد تاريخ اليوم بصيغة متوافقة
    $d = date("Y/m/d");

    // الحصول على اسم المستخدم من الجلسة
    $id = $this->session->userdata('username');

    // إعداد الاستعلام الآمن
    $sql = "SELECT * FROM employee_notebook WHERE n4 = ? AND n2 = ?";
    $query = $this->db->query($sql, array($id, $d));

    // إرجاع النتائج كمصفوفة
    return $query->result_array();
}


