      function get_user_target_this_month($id)
{
    date_default_timezone_set('Asia/Riyadh'); // تحديد توقيت الرياض
    $current_month = date('Y/m'); // الشهر الحالي بصيغة yyyy/mm

    $this->db->where('n2', $id);
    $this->db->where('date', $current_month);
    $query = $this->db->get('traget_report');

    return $query->row_array(); // يرجع صف واحد
}






