      function get_ordersdata_order_emkan558452152() {
    $id = $this->session->userdata('username');
    $n2_value = $this->input->post('n2'); // قراءة قيمة n2 من المدخلات

    // بناء الاستعلام الأساسي
    $sql = "SELECT * FROM order_emkan WHERE n7 = ?";
    
    // إضافة شرط n5 إذا كانت قيمة n2 موجودة
    if (!empty($n2_value)) {
        $sql .= " AND n5 = ?";
        $query = $this->db->query($sql, array($id, $n2_value));
    } else {
        $query = $this->db->query($sql, array($id));
    }

    return $query->result_array();
}

function get_ordersdata_order_emkan5584857() {
    $id = $this->session->userdata('username');
    $n2_value = $this->input->post('n2'); // قراءة قيمة n2 من المدخلات
    $n19_value = $this->input->post('n19'); // قراءة قيمة n19 من المدخلات

    // بناء الاستعلام الأساسي
    $sql = "SELECT * FROM order_emkan WHERE n7 = ?";
    $params = array($id); // قائمة المعلمات للاستعلام

    // إضافة شرط n5 إذا كانت قيمة n2 موجودة
    if (!empty($n2_value)) {
        $sql .= " AND n5 = ?";
        $params[] = $n2_value;
    }

    // إضافة شرط n19 إذا كانت قيمة n19 موجودة
    if (!empty($n19_value)) {
        $sql .= " AND n19 = ?";
        $params[] = $n19_value;
    }

    // إضافة ترتيب النتائج
    $sql .= " ORDER BY id DESC";

    // تنفيذ الاستعلام
    $query = $this->db->query($sql, $params);

    return $query->result_array();
}

