  function get_ordersdata_order_emkan5584555214(){
    $id = $this->session->userdata('username');
    $current_month = date('m'); // الشهر الحالي
    $sql = "SELECT * FROM order_emkan WHERE n7 = ? AND MONTH(n1) = ? ORDER BY id DESC;";
    $query = $this->db->query($sql, array($id, $current_month)); // استخدام المعلمات لتجنب حقن SQL
    return $query->result_array();
}





