         public function order_emkan_update($dd){
            date_default_timezone_set('Asia/Riyadh');
            $d=date("Y/m/d");
            $m=date("Y/m");
            $y=date("Y");
            $day=date("l");
            $time = date("H:i:s");
            $data = array(
                
                 'status'=> '1',
                 'status_up'=> '1',
                 'date_sup'=> $d,
                 'day_sup'=> $day,
                 'time_sup'=> $time,
               
            );
            $this->db->where('id', $dd);
            return $this->db->update('order_emkan', $data);
       }

        public function task_update($task_id) {
    // قراءة الحالة الجديدة من بيانات POST
    $task_status = $this->input->post('task_status');

    if (!$task_status) {
        // لو ما أرسل حالة ➔ أرجع خطأ
        show_error('لم يتم تحديد حالة المهمة.', 400);
    }

    // تجهيز البيانات للتحديث
    $data = array(
        'status' => $task_status
    );

    // تحديث السجل بناءً على ID المرسل
    $this->db->where('id', $task_id);
    $update = $this->db->update('tasks', $data);

    if ($update) {
        // لو نجح التحديث
        redirect('/users/tasks'); // غيرها حسب المكان اللي تبي تروح له بعد الحفظ
    } else {
        show_error('حدث خطأ أثناء تحديث المهمة.', 500);
    }
}

public function time_update($task_id) {
    // قراءة التاريخ الجديد من الفورم
    $new_due_date = $this->input->post('new_due_date');

    if (!$new_due_date) {
        show_error('لم يتم تحديد تاريخ جديد.', 400);
    }

    // تجهيز بيانات التحديث
    $data = array(
        'dedline' => $new_due_date // تأكد أن عندك عمود اسمه due_date في جدول tasks
    );

    $this->db->where('id', $task_id);
    $update = $this->db->update('tasks', $data);

    if ($update) {
        redirect('/users/tasks'); // عدل هذا المسار حسب أين تريد العودة بعد الحفظ
    } else {
        show_error('حدث خطأ أثناء تمديد المهمة.', 500);
    }
}





