function get_ordersdata_order_emkan_billfold_main6_1($offset = 0) {
    $user_id = $this->session->userdata('username');
    $sql = "
        SELECT DISTINCT n2, id, k1 
        FROM $this->billfold 
        WHERE k1 = 'وعد سداد' 
        AND n2 IN (
            SELECT n1 
            FROM $this->attribution 
            WHERE n3 = ?
        )
        ORDER BY id ASC
        LIMIT 1 OFFSET ?
    ";
    $query = $this->db->query($sql, array($user_id, intval($offset))); // تحويل $offset إلى عدد صحيح باستخدام intval
    return $query->row_array(); // جلب الصف المطلوب فقط
}


