public function get_users_by_sub11180() {
    $id = $this->session->userdata('username');

    // تحديد أول وآخر يوم من الشهر الحالي
    date_default_timezone_set('Asia/Riyadh');
    $start_of_month = date("Y/m/01");
    $end_of_month = date("Y/m/t");

    // استعلام للحصول على الموظفين وترتيبهم بناءً على مجموع السداد
    $sql = "
        SELECT 
            u.name, 
            u.username,
            u.project_name, 
            COALESCE(SUM(er.n2), 0) AS total_sdad
        FROM 
            users u
        LEFT JOIN 
            employee_reimbursements er 
        ON 
            u.username = er.n6 
            AND er.n8 >= ? 
            AND er.n8 <= ? 
            AND er.status <= 1
        WHERE 
            u.sub_id = ?
        GROUP BY 
            u.username
        ORDER BY 
            total_sdad DESC
    ";

    // تنفيذ الاستعلام
    $query = $this->db->query($sql, array($start_of_month, $end_of_month, $id));

    // إرجاع النتائج
    return $query->result_array();
}

