function get_project_reimbursement_report777() {
    // تحديد المنطقة الزمنية
    date_default_timezone_set('Asia/Riyadh');

    // الحصول على تاريخ الشهر الحالي
    $start_date = date("Y/m/01"); // بداية الشهر (أول يوم في الشهر)
    $end_date = date("Y/m/t");    // نهاية الشهر (آخر يوم في الشهر)

    // الحصول على تاريخ اليوم
    $today_date = date("Y/m/d");  // تاريخ اليوم (YYYY/MM/DD)

    // SQL لجلب مجموع السدادات (n2) لكل مشروع لهذا الشهر
    $sql = "SELECT 
                project_id, 
                SUM(n2) AS total_reimbursement,
                (SELECT SUM(n2) FROM employee_reimbursements WHERE project_id = er.project_id AND n8 = ?) AS total_reimbursement_today
            FROM employee_reimbursements er
            WHERE status = 1
            AND n8 BETWEEN ? AND ?
            GROUP BY project_id";

    // تنفيذ الاستعلام باستخدام استعلامات آمنة
    $query = $this->db->query($sql, array($today_date, $start_date, $end_date));

    // إرجاع النتائج كمصفوفة
    return $query->result_array();
}

function get_project_reimbursement_report7778() {
    // تحديد المنطقة الزمنية
    date_default_timezone_set('Asia/Riyadh');

    // الحصول على تاريخ الشهر الحالي
    $start_date = date("Y/m/01"); // بداية الشهر (أول يوم في الشهر)
    $end_date = date("Y/m/t");    // نهاية الشهر (آخر يوم في الشهر)

    // الحصول على تاريخ اليوم
    $today_date = date("Y/m/d");  // تاريخ اليوم (YYYY/MM/DD)

    // SQL لجلب مجموع السدادات (n2) لكل مشرف لهذا الشهر مع الترتيب حسب أعلى سداد شهري
    $sql = "SELECT 
                x3 AS supervisor_name,  -- اسم المشرف
                project_id, 
                SUM(n2) AS total_reimbursement,
                (SELECT SUM(n2) 
                 FROM employee_reimbursements 
                 WHERE x3 = er.x3 AND n8 = ?) AS total_reimbursement_today
            FROM employee_reimbursements er
            WHERE status = 1
            AND n8 BETWEEN ? AND ?
            GROUP BY x3, project_id
            ORDER BY total_reimbursement DESC";  // ترتيب النتائج حسب أعلى مجموع سداد شهري

    // تنفيذ الاستعلام باستخدام استعلامات آمنة
    $query = $this->db->query($sql, array($today_date, $start_date, $end_date));

    // إرجاع النتائج كمصفوفة
    return $query->result_array();
}







