    $end_of_month = date("Y/m/t");   // آخر يوم في الشهر الحالي

    // SQL لجلب البيانات بناءً على الفترة الزمنية المحددة و id2
    $sql = "SELECT *
            FROM employee_reimbursements
            WHERE n8 BETWEEN ? AND ? AND n1 = ?";

    // تنفيذ الاستعلام باستخدام استعلامات آمنة
    $query = $this->db->query($sql, array($start_of_month, $end_of_month, $id2));

    // إرجاع النتائج كمصفوفة
    return $query->result_array();
}

