public function get_withdrawn_full_report111()
{
    $sql = "
        SELECT 
            COUNT(*) AS withdrawn_count,                             -- عدد السجلات المسحوبة
            COUNT(DISTINCT o.cic) AS unique_clients_count,           -- عدد العملاء الفريدين المسحوبين
            COALESCE(SUM(o.TOTAL_RESIDUAL_DEBT), 0) AS total_debt,  -- المديونية المسحوبة

            -- إجمالي المديونية في old1
            (
                SELECT COALESCE(SUM(TOTAL_RESIDUAL_DEBT), 0)
                FROM old1
            ) AS total_debt_old,

            -- إجمالي المديونية في new1
            (
                SELECT COALESCE(SUM(TOTAL_RESIDUAL_DEBT), 0)
                FROM new1
            ) AS total_debt_new,

            -- إجمالي العملاء في old1
            (
                SELECT COUNT(DISTINCT cic)
                FROM old1
            ) AS total_clients

        FROM old1 o
        LEFT JOIN new1 n ON o.cic = n.cic
        WHERE n.cic IS NULL
    ";

    $query = $this->db->query($sql);
    $result = $query->row_array();

    // نسبة المديونية المسحوبة من إجمالي مديونية old1
    $result['debt_percentage'] = $result['total_debt_old'] > 0
        ? round(($result['total_debt'] / $result['total_debt_old']) * 100, 2)
        : 0;

    // نسبة العملاء المسحوبين من إجمالي عملاء old1
    $result['client_percentage'] = $result['total_clients'] > 0
        ? round(($result['unique_clients_count'] / $result['total_clients']) * 100, 2)
        : 0;

    // الفرق بين مديونية old1 و new1
    $result['debt_difference'] = $result['total_debt_new'] - $result['total_debt_old'];

    return $result;
}

public function get_product_comparison()
{
    $sql = "
        SELECT 
            COALESCE(o.PROD_Name, n.PROD_Name) AS product_name,
            COALESCE(o.count_old, 0) AS count_old,
            COALESCE(n.count_new, 0) AS count_new,
