public function get_product_comparison11()
{
    $sql = "
        WITH
        -- تصنيف العميل حسب أولوية المنتج
        ranked_old AS (
            SELECT *, 
                ROW_NUMBER() OVER (PARTITION BY cic ORDER BY 
                    CASE 
                        WHEN PROD_Name = 'Car Leasing' THEN 1
                        WHEN PROD_Name = 'Watani' THEN 2
                        WHEN PROD_Name = 'Visa Inhouse' THEN 3
                        ELSE 4
                    END
                ) AS rn
            FROM old1
            WHERE Employee_Name = 'MARSOOM (0_1)'
        ),
        ranked_new AS (
            SELECT *, 
                ROW_NUMBER() OVER (PARTITION BY cic ORDER BY 
                    CASE 
                        WHEN PROD_Name = 'Car Leasing' THEN 1
                        WHEN PROD_Name = 'Watani' THEN 2
                        WHEN PROD_Name = 'Visa Inhouse' THEN 3
                        ELSE 4
                    END
                ) AS rn
            FROM new1
            WHERE Employee_Name = 'MARSOOM (0_1)'
        ),
        -- عدد العملاء حسب المنتج الأعلى أولوية
        client_old_summary AS (
            SELECT PROD_Name, COUNT(DISTINCT cic) AS client_old
            FROM ranked_old
            WHERE rn = 1
            GROUP BY PROD_Name
        ),
        client_new_summary AS (
            SELECT PROD_Name, COUNT(DISTINCT cic) AS client_new
            FROM ranked_new
            WHERE rn = 1
            GROUP BY PROD_Name
        ),
        -- العقود والديون بالتكرار
        contract_old_summary AS (
            SELECT PROD_Name, COUNT(*) AS count_old, SUM(TOTAL_RESIDUAL_DEBT) AS debt_old
            FROM old1
            WHERE Employee_Name = 'MARSOOM (0_1)'
            GROUP BY PROD_Name
        ),
        contract_new_summary AS (
            SELECT PROD_Name, COUNT(*) AS count_new, SUM(TOTAL_RESIDUAL_DEBT) AS debt_new
            FROM new1
            WHERE Employee_Name = 'MARSOOM (0_1)'
            GROUP BY PROD_Name
        )

        -- LEFT JOIN
        SELECT 
            COALESCE(o.PROD_Name, n.PROD_Name) AS product_name,
            COALESCE(o.count_old, 0) AS count_old,
            COALESCE(n.count_new, 0) AS count_new,
            COALESCE(n.count_new, 0) - COALESCE(o.count_old, 0) AS difference,
            COALESCE(co.client_old, 0) AS client_old,
            COALESCE(cn.client_new, 0) AS client_new,
            COALESCE(o.debt_old, 0) AS debt_old,
            COALESCE(n.debt_new, 0) AS debt_new
        FROM contract_old_summary o
        LEFT JOIN contract_new_summary n ON o.PROD_Name = n.PROD_Name
        LEFT JOIN client_old_summary co ON o.PROD_Name = co.PROD_Name
        LEFT JOIN client_new_summary cn ON n.PROD_Name = cn.PROD_Name

        UNION

        -- RIGHT JOIN لإظهار المنتجات الجديدة فقط
        SELECT 
            COALESCE(o.PROD_Name, n.PROD_Name),
            COALESCE(o.count_old, 0),
            COALESCE(n.count_new, 0),
            COALESCE(n.count_new, 0) - COALESCE(o.count_old, 0),
            COALESCE(co.client_old, 0),
            COALESCE(cn.client_new, 0),
            COALESCE(o.debt_old, 0),
            COALESCE(n.debt_new, 0)
        FROM contract_old_summary o
        RIGHT JOIN contract_new_summary n ON o.PROD_Name = n.PROD_Name
        LEFT JOIN client_old_summary co ON o.PROD_Name = co.PROD_Name
        LEFT JOIN client_new_summary cn ON n.PROD_Name = cn.PROD_Name
        WHERE o.PROD_Name IS NULL
    ";

    return $this->db->query($sql)->result_array();
}

