public function get_product_comparison111()
{
    $sql = "
        -- LEFT JOIN: old إلى new
        SELECT 
            COALESCE(o.PROD_Name, n.PROD_Name) AS product_name,
            COALESCE(o.count_old, 0) AS count_old,
            COALESCE(n.count_new, 0) AS count_new,
            COALESCE(n.count_new, 0) - COALESCE(o.count_old, 0) AS difference,
            COALESCE(o.client_old, 0) AS client_old,
            COALESCE(n.client_new, 0) AS client_new,
            COALESCE(do.debt_old, 0) AS debt_old,
            COALESCE(dn.debt_new, 0) AS debt_new
        FROM 
            (
                SELECT 
                    ranked.PROD_Name,
                    COUNT(*) AS count_old,
                    COUNT(DISTINCT ranked.cic) AS client_old
                FROM (
                    SELECT o.*,
                        CASE 
                            WHEN o.PROD_Name = 'Car Leasing' THEN 1
                            WHEN o.PROD_Name = 'Watani' THEN 2
                            WHEN o.PROD_Name = 'Visa Inhouse' THEN 3
                            ELSE 4
                        END AS priority
                    FROM old1 o
                    WHERE o.Employee_Name = 'MARSOOM'
                ) ranked
                JOIN (
                    SELECT cic, MIN(
                        CASE 
                            WHEN PROD_Name = 'Car Leasing' THEN 1
                            WHEN PROD_Name = 'Watani' THEN 2
                            WHEN PROD_Name = 'Visa Inhouse' THEN 3
                            ELSE 4
                        END
                    ) AS min_priority
                    FROM old1
                    WHERE Employee_Name = 'MARSOOM'
                    GROUP BY cic
                ) min_ranks
                ON ranked.cic = min_ranks.cic AND ranked.priority = min_ranks.min_priority
                GROUP BY ranked.PROD_Name
            ) o

        LEFT JOIN 
            (
                SELECT 
                    ranked.PROD_Name,
                    COUNT(*) AS count_new,
                    COUNT(DISTINCT ranked.cic) AS client_new
                FROM (
                    SELECT n.*,
                        CASE 
                            WHEN n.PROD_Name = 'Car Leasing' THEN 1
                            WHEN n.PROD_Name = 'Watani' THEN 2
                            WHEN n.PROD_Name = 'Visa Inhouse' THEN 3
                            ELSE 4
                        END AS priority
                    FROM new1 n
                    WHERE n.Employee_Name = 'MARSOOM'
                ) ranked
                JOIN (
                    SELECT cic, MIN(
                        CASE 
                            WHEN PROD_Name = 'Car Leasing' THEN 1
                            WHEN PROD_Name = 'Watani' THEN 2
                            WHEN PROD_Name = 'Visa Inhouse' THEN 3
                            ELSE 4
                        END
                    ) AS min_priority
                    FROM new1
                    WHERE Employee_Name = 'MARSOOM'
                    GROUP BY cic
                ) min_ranks
                ON ranked.cic = min_ranks.cic AND ranked.priority = min_ranks.min_priority
                GROUP BY ranked.PROD_Name
            ) n 
        ON o.PROD_Name = n.PROD_Name

        -- LEFT JOIN المديونية بالتكرار
        LEFT JOIN (
            SELECT PROD_Name, SUM(TOTAL_RESIDUAL_DEBT) AS debt_old
            FROM old1
            WHERE Employee_Name = 'MARSOOM'
            GROUP BY PROD_Name
        ) do ON do.PROD_Name = o.PROD_Name

        LEFT JOIN (
            SELECT PROD_Name, SUM(TOTAL_RESIDUAL_DEBT) AS debt_new
            FROM new1
            WHERE Employee_Name = 'MARSOOM'
            GROUP BY PROD_Name
        ) dn ON dn.PROD_Name = n.PROD_Name

        -- RIGHT JOIN: من new إلى old لإكمال المنتجات الجديدة غير الموجودة في القديمة
        UNION

        SELECT 
            COALESCE(o.PROD_Name, n.PROD_Name) AS product_name,
            COALESCE(o.count_old, 0) AS count_old,
            COALESCE(n.count_new, 0) AS count_new,
            COALESCE(n.count_new, 0) - COALESCE(o.count_old, 0) AS difference,
            COALESCE(o.client_old, 0) AS client_old,
            COALESCE(n.client_new, 0) AS client_new,
            COALESCE(do.debt_old, 0) AS debt_old,
            COALESCE(dn.debt_new, 0) AS debt_new
        FROM 
            (
                SELECT 
                    ranked.PROD_Name,
                    COUNT(*) AS count_old,
                    COUNT(DISTINCT ranked.cic) AS client_old
                FROM (
                    SELECT o.*,
                        CASE 
                            WHEN o.PROD_Name = 'Car Leasing' THEN 1
                            WHEN o.PROD_Name = 'Watani' THEN 2
                            WHEN o.PROD_Name = 'Visa Inhouse' THEN 3
                            ELSE 4
                        END AS priority
                    FROM old1 o
                    WHERE o.Employee_Name = 'MARSOOM'
                ) ranked
                JOIN (
                    SELECT cic, MIN(
                        CASE 
                            WHEN PROD_Name = 'Car Leasing' THEN 1
                            WHEN PROD_Name = 'Watani' THEN 2
                            WHEN PROD_Name = 'Visa Inhouse' THEN 3
                            ELSE 4
                        END
                    ) AS min_priority
                    FROM old1
                    WHERE Employee_Name = 'MARSOOM'
                    GROUP BY cic
                ) min_ranks
                ON ranked.cic = min_ranks.cic AND ranked.priority = min_ranks.min_priority
                GROUP BY ranked.PROD_Name
            ) o

        RIGHT JOIN 
            (
                SELECT 
                    ranked.PROD_Name,
                    COUNT(*) AS count_new,
                    COUNT(DISTINCT ranked.cic) AS client_new
                FROM (
                    SELECT n.*,
                        CASE 
                            WHEN n.PROD_Name = 'Car Leasing' THEN 1
                            WHEN n.PROD_Name = 'Watani' THEN 2
                            WHEN n.PROD_Name = 'Visa Inhouse' THEN 3
                            ELSE 4
                        END AS priority
                    FROM new1 n
                    WHERE n.Employee_Name = 'MARSOOM'
                ) ranked
                JOIN (
                    SELECT cic, MIN(
                        CASE 
                            WHEN PROD_Name = 'Car Leasing' THEN 1
                            WHEN PROD_Name = 'Watani' THEN 2
                            WHEN PROD_Name = 'Visa Inhouse' THEN 3
                            ELSE 4
                        END
                    ) AS min_priority
                    FROM new1
                    WHERE Employee_Name = 'MARSOOM'
                    GROUP BY cic
                ) min_ranks
                ON ranked.cic = min_ranks.cic AND ranked.priority = min_ranks.min_priority
                GROUP BY ranked.PROD_Name
            ) n 
        ON o.PROD_Name = n.PROD_Name
        LEFT JOIN (
            SELECT PROD_Name, SUM(TOTAL_RESIDUAL_DEBT) AS debt_old
            FROM old1
            WHERE Employee_Name = 'MARSOOM'
            GROUP BY PROD_Name
        ) do ON do.PROD_Name = o.PROD_Name
        LEFT JOIN (
            SELECT PROD_Name, SUM(TOTAL_RESIDUAL_DEBT) AS debt_new
            FROM new1
            WHERE Employee_Name = 'MARSOOM'
            GROUP BY PROD_Name
        ) dn ON dn.PROD_Name = n.PROD_Name
        WHERE o.PROD_Name IS NULL
    ";

    $query = $this->db->query($sql);
    return $query->result_array();
}



public function get_product_comparison_fast_contracts_and_debts()
{
    $sql = "
        -- تصنيف العملاء حسب الأولوية للقديم
        WITH ranked_old_clients AS (
            SELECT *, 
                ROW_NUMBER() OVER (PARTITION BY cic ORDER BY 
                    CASE 
                        WHEN PROD_Name = 'Car Leasing' THEN 1
                        WHEN PROD_Name = 'Watani' THEN 2
                        WHEN PROD_Name = 'Visa Inhouse' THEN 3
                        ELSE 4
                    END
                ) AS rn
            FROM old1
            WHERE Employee_Name = 'MARSOOM'
        ),
        
        -- تصنيف العملاء حسب الأولوية للجديد
        ranked_new_clients AS (
            SELECT *, 
                ROW_NUMBER() OVER (PARTITION BY cic ORDER BY 
                    CASE 
                        WHEN PROD_Name = 'Car Leasing' THEN 1
                        WHEN PROD_Name = 'Watani' THEN 2
                        WHEN PROD_Name = 'Visa Inhouse' THEN 3
                        ELSE 4
                    END
                ) AS rn
            FROM new1
            WHERE Employee_Name = 'MARSOOM'
        ),

        -- إجماليات العقود والمديونية من old1 (بالتكرار)
        old_summary AS (
            SELECT PROD_Name, COUNT(*) AS count_old, SUM(TOTAL_RESIDUAL_DEBT) AS debt_old
            FROM old1
            WHERE Employee_Name = 'MARSOOM'
            GROUP BY PROD_Name
        ),

        -- إجماليات العقود والمديونية من new1 (بالتكرار)
        new_summary AS (
            SELECT PROD_Name, COUNT(*) AS count_new, SUM(TOTAL_RESIDUAL_DEBT) AS debt_new
            FROM new1
            WHERE Employee_Name = 'MARSOOM'
            GROUP BY PROD_Name
        ),

        -- إجماليات العملاء المميزين من old1 (مرة واحدة لكل عميل)
        old_clients AS (
            SELECT PROD_Name, COUNT(DISTINCT cic) AS client_old
            FROM ranked_old_clients
            WHERE rn = 1
            GROUP BY PROD_Name
        ),

        -- إجماليات العملاء المميزين من new1 (مرة واحدة لكل عميل)
        new_clients AS (
            SELECT PROD_Name, COUNT(DISTINCT cic) AS client_new
            FROM ranked_new_clients
            WHERE rn = 1
            GROUP BY PROD_Name
        )

        -- الدمج النهائي
        SELECT 
            COALESCE(o.PROD_Name, n.PROD_Name) AS product_name,
            COALESCE(o.count_old, 0) AS count_old,
            COALESCE(n.count_new, 0) AS count_new,
            COALESCE(n.count_new, 0) - COALESCE(o.count_old, 0) AS difference,
            COALESCE(oc.client_old, 0) AS client_old,
            COALESCE(nc.client_new, 0) AS client_new,
            COALESCE(o.debt_old, 0) AS debt_old,
            COALESCE(n.debt_new, 0) AS debt_new
        FROM old_summary o
        LEFT JOIN new_summary n ON o.PROD_Name = n.PROD_Name
        LEFT JOIN old_clients oc ON o.PROD_Name = oc.PROD_Name
        LEFT JOIN new_clients nc ON n.PROD_Name = nc.PROD_Name

        UNION

        SELECT 
            COALESCE(o.PROD_Name, n.PROD_Name),
            COALESCE(o.count_old, 0),
            COALESCE(n.count_new, 0),
            COALESCE(n.count_new, 0) - COALESCE(o.count_old, 0),
            COALESCE(oc.client_old, 0),
            COALESCE(nc.client_new, 0),
            COALESCE(o.debt_old, 0),
            COALESCE(n.debt_new, 0)
        FROM old_summary o
        RIGHT JOIN new_summary n ON o.PROD_Name = n.PROD_Name
        LEFT JOIN old_clients oc ON o.PROD_Name = oc.PROD_Name
        LEFT JOIN new_clients nc ON n.PROD_Name = nc.PROD_Name
        WHERE o.PROD_Name IS NULL
    ";

    return $this->db->query($sql)->result_array();
}


