public function get_new_entries_from_marsoom_fast()
{
    // 1. قائمة cic الموجودة في old1
    $old_cics = $this->get_all_old1_cics();

    if (empty($old_cics)) {
        // كلهم جدد بما إن القديم فاضي
        $where_not_in = '';
    } else {
        // نحضر صيغة IN (...), ونُهندمها
        $escaped_old_cics = array_map(function($cic) {
            return $this->db->escape(trim($cic));
        }, $old_cics);
        $in_clause = implode(',', $escaped_old_cics);
        $where_not_in = "AND TRIM(cic) NOT IN ($in_clause)";
    }

    // 2. جلب السجلات من new1 للموظف MARSOOM والتي ليست موجودة في old1
    $sql = "
        SELECT 
            COUNT(*) AS new_count,
            COUNT(DISTINCT cic) AS unique_clients,
            COALESCE(SUM(TOTAL_RESIDUAL_DEBT), 0) AS total_debt
        FROM new1
        WHERE Employee_Name = 'MARSOOM'
        $where_not_in
    ";

    $query = $this->db->query($sql);
    return $query->row_array();
}


