public function get_marsoom_summary_main()
{
    $sql = "
        SELECT 
            COUNT(*) AS record_count,
            COUNT(DISTINCT cic) AS unique_clients,
            COALESCE(SUM(TOTAL_RESIDUAL_DEBT), 0) AS total_debt,

            (
                SELECT COALESCE(SUM(TOTAL_RESIDUAL_DEBT), 0) 
                FROM new1 
                WHERE Employee_Name = 'MARSOOM'
            ) AS total_debt_new,

            (
                SELECT COUNT(DISTINCT cic) 
                FROM new1 
                WHERE Employee_Name = 'MARSOOM'
            ) AS total_clients_new,

            (
                SELECT COUNT(*) 
                FROM old1 
                WHERE Employee_Name = 'MARSOOM'
            ) AS total_records_old,

            (
                SELECT COUNT(DISTINCT cic) 
                FROM old1 
                WHERE Employee_Name = 'MARSOOM'
            ) AS total_clients_old,

            (
                SELECT COALESCE(SUM(TOTAL_RESIDUAL_DEBT), 0) 
                FROM old1 
                WHERE Employee_Name = 'MARSOOM'
            ) AS total_debt_old

        FROM new1
        WHERE Employee_Name = 'MARSOOM'
    ";

    $query = $this->db->query($sql);
    $r = $query->row_array();

    // حساب النسب من new1
    $r['debt_percentage'] = $r['total_debt_new'] > 0
        ? round(($r['total_debt'] / $r['total_debt_new']) * 100, 2)
        : 0;

    $r['client_percentage'] = $r['total_clients_new'] > 0
        ? round(($r['unique_clients'] / $r['total_clients_new']) * 100, 2)
        : 0;

    // حساب النسب مقابل old1
    $r['debt_percentage_vs_old'] = $r['total_debt_old'] > 0
        ? round(($r['total_debt'] / $r['total_debt_old']) * 100, 2)
        : 0;

    $r['client_percentage_vs_old'] = $r['total_clients_old'] > 0
        ? round(($r['unique_clients'] / $r['total_clients_old']) * 100, 2)
        : 0;

    $r['record_percentage_vs_old'] = $r['total_records_old'] > 0
        ? round(($r['record_count'] / $r['total_records_old']) * 100, 2)
        : 0;

    return $r;
}


