public function get_full_comparison_report()
{
    $sql = "
        SELECT 
            -- المسحوبات
            COUNT(*) AS withdrawn_count,
            COUNT(DISTINCT o.cic) AS unique_clients_count,
            COALESCE(SUM(o.TOTAL_RESIDUAL_DEBT), 0) AS total_debt,

            -- إضافات جديدة
            (
                SELECT COUNT(*) FROM new1 n
                LEFT JOIN old1 o ON n.cic = o.cic
                WHERE o.cic IS NULL
            ) AS new_count,

            (
                SELECT COUNT(DISTINCT n.cic) FROM new1 n
                LEFT JOIN old1 o ON n.cic = o.cic
                WHERE o.cic IS NULL
            ) AS new_unique_clients,

            (
                SELECT COALESCE(SUM(n.TOTAL_RESIDUAL_DEBT), 0) FROM new1 n
                LEFT JOIN old1 o ON n.cic = o.cic
                WHERE o.cic IS NULL
            ) AS new_debt,

            -- إجماليات
            (SELECT COALESCE(SUM(TOTAL_RESIDUAL_DEBT), 0) FROM old1) AS total_debt_old,
            (SELECT COALESCE(SUM(TOTAL_RESIDUAL_DEBT), 0) FROM new1) AS total_debt_new,
            (SELECT COUNT(DISTINCT cic) FROM old1) AS total_clients_old,
            (SELECT COUNT(DISTINCT cic) FROM new1) AS total_clients_new
        FROM old1 o
        LEFT JOIN new1 n ON o.cic = n.cic
        WHERE n.cic IS NULL
    ";

    $query = $this->db->query($sql);
    $result = $query->row_array();

    // النسب
    $result['debt_percentage'] = $result['total_debt_old'] > 0
        ? round(($result['total_debt'] / $result['total_debt_old']) * 100, 2)
        : 0;

    $result['client_percentage'] = $result['total_clients_old'] > 0
        ? round(($result['unique_clients_count'] / $result['total_clients_old']) * 100, 2)
        : 0;

    $result['debt_difference'] = $result['total_debt_new'] - $result['total_debt_old'];

    $result['new_debt_percentage'] = $result['total_debt_new'] > 0
        ? round(($result['new_debt'] / $result['total_debt_new']) * 100, 2)
        : 0;

    $result['new_client_percentage'] = $result['total_clients_new'] > 0
        ? round(($result['new_unique_clients'] / $result['total_clients_new']) * 100, 2)
        : 0;

    return $result;
}


