    public function get_top_and_bottom_achievers() {
        $current_month = date('Y-m');

        $sql = "
            SELECT 
                t.n2 AS employee_id,
                t.n1 AS employee_name,
                t.n6 AS project_name,
                t.n3 AS supervisor_name,
                t.n10 AS manager_name,
                t.n8 AS target_amount,
                COALESCE(SUM(CASE 
                    WHEN DATE_FORMAT(e.n8, '%Y-%m') = ? AND e.status = '1' THEN e.n2 
                    ELSE 0 END), 0) AS total_paid,
                ROUND(
                    COALESCE(SUM(CASE 
                        WHEN DATE_FORMAT(e.n8, '%Y-%m') = ? AND e.status = '1' THEN e.n2 
                        ELSE 0 END), 0) 
                    / NULLIF(t.n8, 0) * 100, 2
                ) AS achievement_percentage
            FROM traget_report t
            LEFT JOIN employee_reimbursements e ON e.n6 = t.n2
            GROUP BY t.n2, t.n1, t.n6, t.n3, t.n10, t.n8
            ORDER BY achievement_percentage DESC
        ";

        $query = $this->db->query($sql, [$current_month, $current_month]);
        $result = $query->result_array();

        $top_10 = array_slice($result, 0, 10);
        $bottom_5 = array_slice(array_reverse($result), 0, 5);

        // تصنيفات
        $supervisor_data = [];
        $manager_data = [];
        $project_data = [];

        foreach ($result as $row) {
            // المشرفين حسب المشروع
            if (!empty($row['supervisor_name']) && !empty($row['project_name'])) {
                $key = $row['supervisor_name'] . ' | ' . $row['project_name'];
                $supervisor_data[$key]['name'] = $row['supervisor_name'];
                $supervisor_data[$key]['project'] = $row['project_name'];
                $supervisor_data[$key]['values'][] = $row['achievement_percentage'];
                $supervisor_data[$key]['target'][] = $row['target_amount'];
                $supervisor_data[$key]['paid'][] = $row['total_paid'];
            }

            // المدراء حسب المشروع
            if (!empty($row['manager_name']) && !empty($row['project_name'])) {
                $key = $row['manager_name'] . ' | ' . $row['project_name'];
                $manager_data[$key]['name'] = $row['manager_name'];
                $manager_data[$key]['project'] = $row['project_name'];
                $manager_data[$key]['values'][] = $row['achievement_percentage'];
                $manager_data[$key]['target'][] = $row['target_amount'];
                $manager_data[$key]['paid'][] = $row['total_paid'];
            }

            // المشاريع لكل مدير بشكل منفصل
            if (!empty($row['project_name']) && !empty($row['manager_name'])) {
                $key = $row['project_name'] . ' | ' . $row['manager_name'];
                $project_data[$key]['project_name'] = $row['project_name'];
                $project_data[$key]['manager'] = $row['manager_name'];
                $project_data[$key]['values'][] = $row['achievement_percentage'];
                $project_data[$key]['target'][] = $row['target_amount'];
                $project_data[$key]['paid'][] = $row['total_paid'];
            }
        }

        $top_supervisors = $this->rank_with_project($supervisor_data, 5);
        $all_managers = $this->rank_with_project($manager_data);
        $all_projects = $this->rank_projects_by_manager($project_data);
        $all_supervisors = $this->rank_with_project($supervisor_data);

        $best_supervisor = !empty($top_supervisors[0]) ? $top_supervisors[0] : null;
        $best_manager = !empty($all_managers[0]) ? $all_managers[0] : null;
        $best_project = !empty($all_projects[0]) ? $all_projects[0] : null;

        return [
            'top_10' => $top_10,
            'bottom_5' => $bottom_5,
            'top_supervisors' => $top_supervisors,
            'all_supervisors_ranked' => $all_supervisors,
            'all_managers_ranked' => $all_managers,
            'all_projects_ranked' => $all_projects,
            'best_supervisor' => $best_supervisor,
            'best_manager' => $best_manager,
            'best_project' => $best_project,
        ];
    }
