function add_sadad113($x2, $names) {
    if ($this->input->post('mobile1') == "") {
        $mobile = $this->input->post('mobile');
    } else {
        $mobile = $this->input->post('mobile1');
    }

    date_default_timezone_set('Asia/Riyadh');
    $d = date("Y/m/d");
    $time = date("H:i:s");
    $status = 0;

    // تنظيف الأرقام من الفواصل والمسافات
    function clean_number($value) {
        return floatval(str_replace([',', ' '], '', $value));
    }

    // جلب بيانات القسط من جدول billfold1 بناءً على رقم العقد
    $this->db->where('n3', $this->input->post('n1'));
    $query = $this->db->get('billfold1');
    $bill = $query->row_array();

    $payment_type = null;
    $payment_status = null;

    if ($bill) {
        $installment_amount = clean_number($bill['m1']); // مبلغ القسط
        $impact_amount = clean_number($bill['z3']); // مبلغ التأثير
        $paid_amount = clean_number($this->input->post('n2')); // المبلغ المدفوع

        if ($paid_amount >= $installment_amount) {
            $payment_status = 1;
            $payment_type = 'المبلغ يساوي القسط او اكبر من القسط';
        } elseif ($paid_amount >= $impact_amount) {
            $payment_status = 1;
            $payment_type = 'المبلغ يساوي مبلغ التأثير او اعلى';
        }
    }

    $data = array(
        'n1' => $this->input->post('n1'),
        'x1' => $this->input->post('x1'),
        'n2' => $this->input->post('n2'),
        'n3' => $this->input->post('n3'),
        'n4' => $this->input->post('n4'),
        'n5' => $this->input->post('n5'),
        'product' => $this->input->post('product'),
        'n6' => $this->session->userdata('username'),
        'n7' => $this->session->userdata('name'),
        'project' => $this->session->userdata('project_name'),
        'project_id' => $this->session->userdata('project'),
        'n8' => $d,
        'n9' => $time,
        'status' => $status,
        'mobile' => $mobile,
        'file4' => $names,
        'x2' => $x2,
        'x3' => $this->session->userdata('sub_id'),
        'x4' => $this->session->userdata('suberviser')
    );

    // فقط إذا تحقق الشرط نضيف هذه القيم
    if ($payment_status !== null && $payment_type !== null) {
        $data['payment_status'] = $payment_status;
        $data['payment_type'] = $payment_type;
    }

    return $this->db->insert('employee_reimbursements', $data);
}


