function add_hh($id, $type, $n2,$n22)
{
    date_default_timezone_set('Asia/Riyadh');
    $d = date("Y/m/d");
    $time = date("H:i:s");

    // تأكد من كتابة POST بالأحرف الصغيرة لتعمل بشكل صحيح في CodeIgniter
    $new_value = $this->input->post('n2');

    $data = array(
        'name'     => $this->session->userdata('name'),
        'username' => $this->session->userdata('username'),
        'date'     => $d,
        'time'     => $time,
        'type'     => $type,
        'old'      => $n2,
        'new'      => $new_value,
        'emp_id'   => $id,
        'emp_name'   => $n22
    );

    return $this->db->insert('hh', $data);
}


