         public function distribute_clients_priority_by_supervisor($project_id, $code, $supervisor_id)
{
   // خريطة جميع جداول attribution
$attribution_tables = [
    1  => 'attribution',
    5  => 'attribution1',
    55 => 'attribution2',
    4  => 'attribution3',
    3  => 'attribution4',
    33 => 'attribution5',
    6  => 'attribution6',
    7  => 'attribution7',
    2  => 'attribution8',
    8  => 'attribution9',
    9  => 'attribution10',
    10 => 'attribution11',
    11 => 'attribution12',
    12 => 'attribution13',
    14 => 'attribution14',
    15 => 'attribution15'
];

// تحقق من المشروع
if (!isset($attribution_tables[$project_id])) {
    return false; // المشروع غير مدعوم
}

// تحديد الجدول حسب project_id
$table = $attribution_tables[$project_id];


    // 1. جلب العملاء المراد توزيعهم
    $clients = $this->db->query("
        SELECT * FROM $table 
        WHERE n3 = ? 
        ORDER BY id ASC
    ", [$code])->result_array();

    if (empty($clients)) {
        return false;
    }

    // 2. جلب الموظفين المؤهلين لنفس المشرف فقط (h4 = $supervisor_id) + تحقق من users
    $eligible_employees = $this->db->query("
        SELECT DISTINCT a.n3, a.h4, a.h5, a.h7
        FROM $table a
        INNER JOIN users u ON a.n3 = u.username
        WHERE a.n3 != ? AND a.h4 = ?
    ", [$code, $supervisor_id])->result_array();

    if (empty($eligible_employees)) {
        return false;
    }

    // 3. حساب عدد العملاء الحالي لكل موظف في الجدول كامل
    foreach ($eligible_employees as &$employee) {
        $count = $this->db->query("
            SELECT COUNT(*) AS total 
            FROM $table 
            WHERE n3 = ?
        ", [$employee['n3']])->row()->total;

        $employee['current_count'] = $count;
    }

    // 4. توزيع العملاء واحد واحد حسب الأقل عملاء
    foreach ($clients as $client) {
        // إعادة ترتيب الموظفين حسب الأقل عملاء
        usort($eligible_employees, function($a, $b) {
            return $a['current_count'] <=> $b['current_count'];
        });

        // اختيار الموظف الأقل عملاء
        $employee = &$eligible_employees[0];

        // تحديث العميل
        $this->db->where('id', $client['id']);
        $this->db->update($table, [
            'n3'         => $employee['n3'],
            'h4'         => $employee['h4'],
            'h5'         => $employee['h5'],
            'h7'         => $employee['h7'],
            'status_emp'  => 'مجهول',
            'status_emp1' => 'مجهول',
            'emp_det1'    => '',
            'emp_det'     => '',
            'date_emp'    => ''
        ]);

        // زيادة عداد الموظف
        $employee['current_count']++;
    }

    return true;
}

