public function distribute_clients_equal_by_supervisor($project_id, $code, $supervisor_id)
{
    // خريطة جميع جداول attribution
$attribution_tables = [
    1  => 'attribution',
    5  => 'attribution1',
    55 => 'attribution2',
    4  => 'attribution3',
    3  => 'attribution4',
    33 => 'attribution5',
    6  => 'attribution6',
    7  => 'attribution7',
    2  => 'attribution8',
    8  => 'attribution9',
    9  => 'attribution10',
    10 => 'attribution11',
    11 => 'attribution12',
    12 => 'attribution13',
    14 => 'attribution14',
    15 => 'attribution15'
];

// تحقق من المشروع
if (!isset($attribution_tables[$project_id])) {
    return false; // المشروع غير مدعوم
}

// تحديد الجدول حسب project_id
$table = $attribution_tables[$project_id];


    // 1. جلب العملاء المستهدفين فقط (n3 = الكود)
    $clients = $this->db->query("
        SELECT * FROM $table 
        WHERE n3 = ? 
        ORDER BY id ASC
    ", [$code])->result_array();

    if (empty($clients)) {
        return false;
    }

    // 2. جلب الموظفين المؤهلين لنفس المشرف فقط (h4 = $supervisor_id) + تحقق من users
    $eligible_employees = $this->db->query("
        SELECT DISTINCT a.n3, a.h4, a.h5, a.h7
        FROM $table a
        INNER JOIN users u ON a.n3 = u.username
        WHERE a.n3 != ? AND a.h4 = ?
        ORDER BY a.n3 ASC
    ", [$code, $supervisor_id])->result_array();

    if (empty($eligible_employees)) {
        return false;
    }

    // 3. حساب التوزيع بالتساوي
    $client_count   = count($clients);
    $employee_count = count($eligible_employees);

    $base_share = floor($client_count / $employee_count);
    $extra      = $client_count % $employee_count;

    $distribution = [];
    foreach ($eligible_employees as $index => $employee) {
        $distribution[$index] = $base_share + ($extra > 0 ? 1 : 0);
        if ($extra > 0) $extra--;
    }

    // 4. توزيع العملاء
    $client_index = 0;
    foreach ($eligible_employees as $index => $employee) {
        for ($i = 0; $i < $distribution[$index]; $i++) {
            if (!isset($clients[$client_index])) break;

            $this->db->where('id', $clients[$client_index]['id']);
            $this->db->update($table, [
                'n3'         => $employee['n3'],
                'h4'         => $employee['h4'],
                'h5'         => $employee['h5'],
                'h7'         => $employee['h7'],
                'status_emp'  => 'مجهول',
                'status_emp1' => 'مجهول',
                'emp_det1'    => '',
                'emp_det'     => '',
                'date_emp'    => ''
            ]);

            $client_index++;
        }
    }

    return true;
}

