        // نقل العميل للأدنى
        $this->db->where('id', $client['id']);
        $this->db->update($table, [
            'n3' => $minEmp['n3'],
            'h4' => $minEmp['h4'],
            'h5' => $minEmp['h5'],
            'h7' => $minEmp['h7']
        ]);

        // تحديث العدادات
        $minEmp['current_count']++;
        $maxEmp['current_count']--;

        // إعادة ترتيب الموظفين
        usort($employees, function($a, $b) {
            return $a['current_count'] <=> $b['current_count'];
        });

        // إعادة تعيين المؤشرات
        $minIndex = 0;
        $maxIndex = count($employees) - 1;
    }

    return true;
}



public function balance_clients_between_employees_no_stabilizing($project_id)
{
    // خريطة جميع جداول attribution
$attribution_tables = [
    1  => 'attribution',
    5  => 'attribution1',
    55 => 'attribution2',
    4  => 'attribution3',
    3  => 'attribution4',
    33 => 'attribution5',
    6  => 'attribution6',
    7  => 'attribution7',
    2  => 'attribution8',
    8  => 'attribution9',
    9  => 'attribution10',
    10 => 'attribution11',
    11 => 'attribution12',
    12 => 'attribution13',
    14 => 'attribution14',
    15 => 'attribution15'
];

// تحقق من المشروع
if (!isset($attribution_tables[$project_id])) {
    return false; // المشروع غير مدعوم
}

// تحديد الجدول حسب project_id
$table = $attribution_tables[$project_id];


    // 1. جلب جميع الموظفين المؤهلين
    $employees = $this->db->query("
        SELECT DISTINCT a.n3, a.h4, a.h5, a.h7
        FROM $table a
        INNER JOIN users u ON a.n3 = u.username
        ORDER BY a.n3 ASC
    ")->result_array();

    if (empty($employees)) {
        return false;
    }

    // 2. حساب عدد العملاء الحالي لكل موظف
    foreach ($employees as &$employee) {
        $count = $this->db->query("
            SELECT COUNT(*) AS total 
            FROM $table 
            WHERE n3 = ?
        ", [$employee['n3']])->row()->total;

        $employee['current_count'] = $count;
    }

    // 3. ترتيب الموظفين حسب عدد العملاء
    usort($employees, function($a, $b) {
        return $a['current_count'] <=> $b['current_count'];
    });

    // 4. الموازنة: سحب من الأعلى وإعطاء الأدنى
    $minIndex = 0;
    $maxIndex = count($employees) - 1;

    while ($minIndex < $maxIndex) {
        $minEmp = &$employees[$minIndex];
        $maxEmp = &$employees[$maxIndex];

        // إذا الفارق أقل أو يساوي 1 توقف
        if (($maxEmp['current_count'] - $minEmp['current_count']) <= 1) {
            $minIndex++;
            $maxIndex--;
            continue;
        }

        // جلب عميل واحد من الأعلى بشرط status_emp1 = 'مجهول' و stabilizing != 1
        $client = $this->db->query("
            SELECT id 
            FROM $table
            WHERE n3 = ? AND status_emp1 = 'مجهول' AND (stabilizing != 1 OR stabilizing IS NULL)
            ORDER BY id DESC
            LIMIT 1
        ", [$maxEmp['n3']])->row_array();

        if (!$client) {
            // لو ما لقى عملاء تنطبق عليهم الشروط ننقص المؤشر للأعلى ونكمل
            $maxIndex--;
            continue;
        }

        // نقل العميل للأدنى
        $this->db->where('id', $client['id']);
        $this->db->update($table, [
            'n3' => $minEmp['n3'],
            'h4' => $minEmp['h4'],
            'h5' => $minEmp['h5'],
            'h7' => $minEmp['h7']
        ]);

        // تحديث العدادات
        $minEmp['current_count']++;
        $maxEmp['current_count']--;

        // إعادة ترتيب الموظفين بعد التوزيع
        usort($employees, function($a, $b) {
            return $a['current_count'] <=> $b['current_count'];
        });

        // إعادة تعيين المؤشرات
        $minIndex = 0;
        $maxIndex = count($employees) - 1;
    }

    return true;
}


 public function balance_clients_between_employees_no_status_emp1($project_id)
{
    // خريطة جميع جداول attribution
    $attribution_tables = [
        1  => 'attribution',
        5  => 'attribution1',
        55 => 'attribution2',
        4  => 'attribution3',
        3  => 'attribution4',
        33 => 'attribution5',
        6  => 'attribution6',
        7  => 'attribution7',
        2  => 'attribution8',
        8  => 'attribution9',
        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14',
        15 => 'attribution15'
    ];

    // تحقق من المشروع
    if (!isset($attribution_tables[$project_id])) {
        return false; // المشروع غير مدعوم
    }

    // تحديد الجدول حسب project_id
    $table = $attribution_tables[$project_id];

    // 1. جلب جميع الفئات الموجودة
    $categories = $this->db->query("
        SELECT DISTINCT category FROM $table
    ")->result_array();

    if (empty($categories)) {
        return false;
    }

    // 2. معالجة كل فئة على حدة
    foreach ($categories as $catRow) {
        $category = $catRow['category'];

        // 2.1 جلب الموظفين المؤهلين من نفس الفئة
        $employees = $this->db->query("
            SELECT DISTINCT u.username AS n3, u.employee_classification, a.h4, a.h5, a.h7
            FROM users u
            LEFT JOIN $table a ON a.n3 = u.username
            WHERE u.type = 1 AND u.employee_classification = ?
        ", [$category])->result_array();

        if (empty($employees)) {
            continue; // ما في موظفين لهذه الفئة
        }

        // ** تنظيف الفئات الخاطئة أولاً **
        // أي عميل فئته = $category لكن موظفه الحالي فئته مختلفة => ننقله لموظف مناسب بنفس الفئة
        $wrongClients = $this->db->query("
            SELECT a.id
            FROM $table a
            INNER JOIN users u ON a.n3 = u.username
            WHERE a.category = ? 
              AND u.employee_classification != a.category
              AND (a.stabilizing != 1 OR a.stabilizing IS NULL)
        ", [$category])->result_array();

        if (!empty($wrongClients)) {
            foreach ($wrongClients as $client) {
                // اختر أي موظف من نفس الفئة (ممكن نعمل توازن لاحقاً)
                $targetEmp = $employees[array_rand($employees)];

                $this->db->where('id', $client['id']);
                $this->db->update($table, [
                    'n3' => $targetEmp['n3'],
                    'h4' => $targetEmp['h4'],
                    'h5' => $targetEmp['h5'],
                    'h7' => $targetEmp['h7']
                ]);
            }
        }

        // ** بعد التنظيف: نوزع العملاء داخل الفئة بالتساوي **

        // حساب عدد العملاء الحالي لكل موظف
        foreach ($employees as &$emp) {
            $count = $this->db->query("
                SELECT COUNT(*) AS total 
                FROM $table 
                WHERE n3 = ? AND category = ?
            ", [$emp['n3'], $category])->row()->total;

            $emp['current_count'] = $count;
        }

        // ترتيب الموظفين
        usort($employees, function($a, $b) {
            return $a['current_count'] <=> $b['current_count'];
        });

        // الموازنة داخل الفئة
        $minIndex = 0;
        $maxIndex = count($employees) - 1;

        while ($minIndex < $maxIndex) {
            $minEmp = &$employees[$minIndex];
            $maxEmp = &$employees[$maxIndex];

            if (($maxEmp['current_count'] - $minEmp['current_count']) <= 1) {
                $minIndex++;
                $maxIndex--;
                continue;
            }

            // جلب عميل غير مثبت من الأعلى ومن نفس الفئة
            $client = $this->db->query("
                SELECT id
                FROM $table
                WHERE n3 = ? 
                  AND category = ?
                  AND (stabilizing != 1 OR stabilizing IS NULL)
                ORDER BY id DESC
                LIMIT 1
            ", [$maxEmp['n3'], $category])->row_array();

            if (!$client) {
                $maxIndex--;
                continue;
            }

            // نقل العميل للموظف الأقل
            $this->db->where('id', $client['id']);
            $this->db->update($table, [
                'n3' => $minEmp['n3'],
                'h4' => $minEmp['h4'],
                'h5' => $minEmp['h5'],
                'h7' => $minEmp['h7']
            ]);

            // تحديث العدادات
            $minEmp['current_count']++;
            $maxEmp['current_count']--;

            // إعادة ترتيب الموظفين
            usort($employees, function($a, $b) {
                return $a['current_count'] <=> $b['current_count'];
            });

            $minIndex = 0;
            $maxIndex = count($employees) - 1;
        }
    }

    return true;
}


