public function balance_clients_between_employees_all($project_id)
{
    // خريطة جميع جداول attribution
    $attribution_tables = [
        1  => 'attribution',
        5  => 'attribution1',
        55 => 'attribution2',
        4  => 'attribution3',
        3  => 'attribution4',
        33 => 'attribution5',
        6  => 'attribution6',
        7  => 'attribution7',
        2  => 'attribution8',
        8  => 'attribution9',
        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14',
        15 => 'attribution15'
    ];

    // تحقق من المشروع
    if (!isset($attribution_tables[$project_id])) {
        return false; // المشروع غير مدعوم
    }

    // تحديد الجدول حسب project_id
    $table = $attribution_tables[$project_id];

    // 1. جلب الموظفين المؤهلين (type = 1)
    $employees = $this->db->query("
        SELECT DISTINCT a.n3, a.h4, a.h5, a.h7
        FROM $table a
        INNER JOIN users u ON a.n3 = u.username AND u.type = 1
        ORDER BY a.n3 ASC
    ")->result_array();

    if (empty($employees)) {
        return false;
    }

    // 2. جلب العملاء غير المثبتين فقط
    $clients = $this->db->query("
        SELECT id
        FROM $table
        WHERE stabilizing != 1 OR stabilizing IS NULL
        ORDER BY id ASC
    ")->result_array();

    if (empty($clients)) {
        return true; // لا يوجد عملاء غير مثبتين لنوازنهم
    }

    // 3. حساب التوزيع المتساوي للعملاء غير المثبتين
    $total_clients = count($clients);
    $total_employees = count($employees);
    $per_employee = floor($total_clients / $total_employees);
    $extra = $total_clients % $total_employees;

    // 4. توزيع العملاء غير المثبتين فقط
    $index = 0;
    foreach ($employees as $emp) {
        $count_for_emp = $per_employee + ($extra > 0 ? 1 : 0);
        if ($extra > 0) $extra--;

        for ($i = 0; $i < $count_for_emp; $i++) {
            if (!isset($clients[$index])) break;

            $client_id = $clients[$index]['id'];

            // تحديث العميل لهذا الموظف
            $this->db->where('id', $client_id);
            $this->db->update($table, [
                'n3' => $emp['n3'],
                'h4' => $emp['h4'],
                'h5' => $emp['h5'],
                'h7' => $emp['h7']
            ]);

            $index++;
        }
    }

    return true;
}




public function balance_clients_between_employees_all_by_category($project_id)
{
    // خريطة جميع جداول attribution
$attribution_tables = [
    1  => 'attribution',
    5  => 'attribution1',
    55 => 'attribution2',
    4  => 'attribution3',
    3  => 'attribution4',
    33 => 'attribution5',
    6  => 'attribution6',
    7  => 'attribution7',
    2  => 'attribution8',
    8  => 'attribution9',
    9  => 'attribution10',
    10 => 'attribution11',
    11 => 'attribution12',
    12 => 'attribution13',
    14 => 'attribution14',
    15 => 'attribution15'
];

// تحقق من المشروع
if (!isset($attribution_tables[$project_id])) {
    return false; // المشروع غير مدعوم
}

// تحديد الجدول حسب project_id
$table = $attribution_tables[$project_id];


    // 1. جلب جميع الموظفين المؤهلين مع الفئة
    $employees = $this->db->query("
        SELECT DISTINCT a.n3, a.h4, a.h5, a.h7, a.category
        FROM $table a
        INNER JOIN users u ON a.n3 = u.username
        ORDER BY a.category ASC, a.n3 ASC
    ")->result_array();

    if (empty($employees)) {
        return false;
    }

    // 2. حساب عدد العملاء الحالي لكل موظف
    foreach ($employees as &$employee) {
        $count = $this->db->query("
            SELECT COUNT(*) AS total 
            FROM $table 
            WHERE n3 = ?
        ", [$employee['n3']])->row()->total;

        $employee['current_count'] = $count;
    }

    // 3. تقسيم الموظفين حسب الفئة
    $categories = [];
    foreach ($employees as $employee) {
        $categories[$employee['category']][] = $employee;
    }

    // 4. موازنة داخل كل فئة
    foreach ($categories as $cat_employees) {
        // ترتيب الموظفين داخل الفئة حسب عدد العملاء
        usort($cat_employees, function($a, $b) {
            return $a['current_count'] <=> $b['current_count'];
        });

        $minIndex = 0;
        $maxIndex = count($cat_employees) - 1;

        while ($minIndex < $maxIndex) {
            $minEmp = &$cat_employees[$minIndex];
            $maxEmp = &$cat_employees[$maxIndex];

            // إذا الفارق أقل أو يساوي 1 توقف
            if (($maxEmp['current_count'] - $minEmp['current_count']) <= 1) {
                $minIndex++;
                $maxIndex--;
                continue;
            }

            // جلب عميل واحد من الأعلى بشرط stabilizing != 1
            $client = $this->db->query("
                SELECT id 
                FROM $table
                WHERE n3 = ? 
                  AND (stabilizing != 1 OR stabilizing IS NULL)
                  AND category = ?
                ORDER BY id DESC
                LIMIT 1
            ", [$maxEmp['n3'], $maxEmp['category']])->row_array();

            if (!$client) {
                $maxIndex--;
                continue;
            }

            // نقل العميل للأدنى داخل نفس الفئة
            $this->db->where('id', $client['id']);
            $this->db->update($table, [
                'n3' => $minEmp['n3'],
                'h4' => $minEmp['h4'],
                'h5' => $minEmp['h5'],
                'h7' => $minEmp['h7'],
                'category' => $minEmp['category'] // يظل داخل نفس الفئة
            ]);

            // تحديث العدادات
            $minEmp['current_count']++;
            $maxEmp['current_count']--;

            // إعادة ترتيب الموظفين داخل نفس الفئة
            usort($cat_employees, function($a, $b) {
                return $a['current_count'] <=> $b['current_count'];
            });

            $minIndex = 0;
            $maxIndex = count($cat_employees) - 1;
        }
    }

    return true;
}


 public function rotate_clients_between_employees_advanced($project_id)
{
    $attribution_tables = [
        1  => 'attribution',
        5  => 'attribution1',
        55 => 'attribution2',
        4  => 'attribution3',
        3  => 'attribution4',
        33 => 'attribution5',
        6  => 'attribution6',
        7  => 'attribution7',
        2  => 'attribution8',
        8  => 'attribution9',
        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14',
        15 => 'attribution15'
    ];

    if (!isset($attribution_tables[$project_id])) {
        return false;
    }

    $table = $attribution_tables[$project_id];

    // جلب جميع الموظفين وإحصائياتهم
    $employees = $this->db->query("
        SELECT DISTINCT a.n3, a.h4, a.h5, a.h7, a.category
        FROM $table a
        INNER JOIN users u ON a.n3 = u.username
    ")->result_array();

    if (empty($employees)) return false;

    // دالة لحساب إحصائيات موظف معين
    $getStats = function($empId) use ($table) {
        return $this->db->query("
            SELECT 
                COUNT(*) AS total_clients,
                IFNULL(SUM(h1),0) AS total_debt,
                SUM(CASE WHEN status_com = 'معلوم' THEN 1 ELSE 0 END) AS known,
                SUM(CASE WHEN status_com = 'مجهول' THEN 1 ELSE 0 END) AS unknown,
                SUM(CASE WHEN h1 < 50000 THEN 1 ELSE 0 END) AS debt_below_50k,
                SUM(CASE WHEN h1 >= 50000 AND h1 < 100000 THEN 1 ELSE 0 END) AS debt_50_100k,
                SUM(CASE WHEN h1 >= 100000 AND h1 < 150000 THEN 1 ELSE 0 END) AS debt_100_150k,
                SUM(CASE WHEN h1 >= 150000 THEN 1 ELSE 0 END) AS debt_above_150k
            FROM $table
            WHERE n3 = ?
        ", [$empId])->row_array();
    };

    // جلب جميع العملاء القابلين للتدوير
    $clients = $this->db->query("
        SELECT id, n3, h1, status_com, category, n5
        FROM $table
        WHERE (stabilizing != 1 OR stabilizing IS NULL)
    ")->result_array();

    if (empty($clients)) return false;

    // تمرير على كل عميل
    foreach ($clients as $client) {
        $client_debt = (float)$client['h1'];

        // تحديد شريحة الدين
        $debt_segment = 'above_150k';
        if ($client_debt < 50000) {
            $debt_segment = 'below_50k';
        } elseif ($client_debt >= 50000 && $client_debt < 100000) {
            $debt_segment = '50_100k';
        } elseif ($client_debt >= 100000 && $client_debt < 150000) {
            $debt_segment = '100_150k';
        }

        // حساب عمر الدين (بالسنوات)
        $age_years = 0;
        if (!empty($client['n5'])) {
            $age_years = (new DateTime())->diff(new DateTime($client['n5']))->y;
        }

        // فلترة الموظفين حسب الفئة (إن وجدت)
        $filtered_employees = array_filter($employees, function($emp) use ($client) {
            return $emp['category'] === $client['category'] || empty($client['category']);
        });
        if (empty($filtered_employees)) $filtered_employees = $employees;

        // استبعاد الموظف الحالي
        $filtered_employees = array_filter($filtered_employees, function($emp) use ($client) {
            return $emp['n3'] != $client['n3'];
        });

        if (empty($filtered_employees)) continue;

        // ترتيب الموظفين حسب معايير متعددة
        usort($filtered_employees, function($a, $b) use ($getStats, $debt_segment) {
            $statsA = $getStats($a['n3']);
            $statsB = $getStats($b['n3']);

            // 1- الأقل إجمالي مديونية
            if ($statsA['total_debt'] != $statsB['total_debt'])
                return $statsA['total_debt'] <=> $statsB['total_debt'];

            // 2- الأقل عدد عملاء
            if ($statsA['total_clients'] != $statsB['total_clients'])
                return $statsA['total_clients'] <=> $statsB['total_clients'];

            // 3- الأقل في نفس شريحة الدين
            return $statsA["debt_{$debt_segment}"] <=> $statsB["debt_{$debt_segment}"];
        });

        $best_emp = $filtered_employees[0];

        // تحديث العميل
        $this->db->where('id', $client['id']);
        $this->db->update($table, [
            'n3' => $best_emp['n3'],
            'h4' => $best_emp['h4'],
            'h5' => $best_emp['h5'],
            'h7' => $best_emp['h7'],
            'category' => $best_emp['category']
        ]);
    }

    return true;
}

















