        }
    }

    return true;
}


 public function distribute_clients_balanced_smart($project_id, $code)
{
    // تنظيف الكود
    $code_clean = trim($code);

    // 1. خريطة الجداول
    $attribution_tables = [
        1  => 'attribution',
        5  => 'attribution1',
        55 => 'attribution2',
        4  => 'attribution3',
        3  => 'attribution4',
        33 => 'attribution5',
        6  => 'attribution6',
        7  => 'attribution7',
        2  => 'attribution8',
        8  => 'attribution9',
        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14',
        15 => 'attribution15'
    ];

    if (!isset($attribution_tables[$project_id])) return false;
    $table = $attribution_tables[$project_id];

    // 2. العملاء المستهدفين (n3 = $code)
    $clients = $this->db->query("
        SELECT * FROM $table WHERE n3 = ? ORDER BY h1 DESC
    ", [$code_clean])->result_array();

    if (empty($clients)) return false;

    // 3. الموظفين المؤهلين من جدول العملاء + users (type=1) مع استبعاد الكود
    $eligible_employees = $this->db->query("
        SELECT t.n3, t.h4, t.h5, t.h7
        FROM $table t
        INNER JOIN users u ON t.n3 = u.username
        WHERE u.type = 1
          AND u.username != ?
        GROUP BY t.n3, t.h4, t.h5, t.h7
        ORDER BY t.n3 ASC
    ", [$code_clean])->result_array();

    if (empty($eligible_employees)) return false;

    // 4. حساب نصيب كل موظف
    $employee_count = count($eligible_employees);
    $client_count   = count($clients);
    $base_share     = floor($client_count / $employee_count);
    $extra          = $client_count % $employee_count;

    $employees_data = [];
    foreach ($eligible_employees as $emp) {
        $max_clients = $base_share + ($extra > 0 ? 1 : 0);
        if ($extra > 0) $extra--;

        $employees_data[] = [
            'info'        => $emp,
            'max_clients' => $max_clients,
            'assigned'    => [],
            'total_debt'  => 0
        ];
    }

    // 5. توزيع العملاء بالتساوي + موازنة المديونية
    foreach ($clients as $client) {
        usort($employees_data, function($a, $b) {
            return $a['total_debt'] <=> $b['total_debt'];
        });

        foreach ($employees_data as &$emp) {
            if (count($emp['assigned']) < $emp['max_clients']) {
                $emp['assigned'][] = $client;
                $emp['total_debt'] += $client['h1'];
                break;
            }
        }
    }

    // 6. تحديث قاعدة البيانات (وحماية إضافية من الكود)
    foreach ($employees_data as $emp) {
        if (trim($emp['info']['n3']) === $code_clean) continue; // حماية نهائية

        foreach ($emp['assigned'] as $client) {
            $this->db->where('id', $client['id'])->update($table, [
                'n3'         => $emp['info']['n3'],
                'h4'         => $emp['info']['h4'],
                'h5'         => $emp['info']['h5'],
                'h7'         => $emp['info']['h7'],
                'status_emp'  => 'مجهول',
                'status_emp1' => 'مجهول',
                'emp_det1'    => '',
                'emp_det'     => '',
                'date_emp'    => ''
            ]);
        }
    }

    return true;
}





















public function distribute_clients_balanced_fast($project_id, $code)
{
    // خريطة جميع جداول attribution
    $attribution_tables = [
        1  => 'attribution',
        5  => 'attribution1',
        55 => 'attribution2',
        4  => 'attribution3',
        3  => 'attribution4',
        33 => 'attribution5',
        6  => 'attribution6',
        7  => 'attribution7',
        2  => 'attribution8',
        8  => 'attribution9',
        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14',
        15 => 'attribution15'
    ];

    if (!isset($attribution_tables[$project_id])) {
        return false;
    }

    $table = $attribution_tables[$project_id];

    // 1. جلب العملاء المراد توزيعهم فقط
    $clients = $this->db->query("
        SELECT * FROM $table 
        WHERE n3 = ? 
        ORDER BY h1 DESC
    ", [$code])->result_array();

    if (empty($clients)) {
        return false;
    }

    // 2. جلب الموظفين المؤهلين
    $eligible_employees = $this->db->query("
        SELECT a.n3, a.h4, a.h5, a.h7
        FROM $table a
        INNER JOIN users u ON a.n3 = u.username
        WHERE a.n3 != ?
        GROUP BY a.n3, a.h4, a.h5, a.h7
        ORDER BY a.n3 ASC
    ", [$code])->result_array();

    if (empty($eligible_employees)) {
        return false;
    }

    $employee_count = count($eligible_employees);
    $client_count   = count($clients);

    // حساب نصيب كل موظف
    $base_share = floor($client_count / $employee_count);
    $extra = $client_count % $employee_count;

    // مصفوفة توزيع العملاء لكل موظف
    $distribution = [];
    foreach ($eligible_employees as $index => $emp) {
        $distribution[$index] = $base_share + ($extra > 0 ? 1 : 0);
        if ($extra > 0) $extra--;
    }

    // 3. توزيع Round Robin بالعملاء الأغلى أولاً
    $client_index = 0;
    foreach ($distribution as $index => $count) {
        $emp_info = $eligible_employees[$index];
        for ($i = 0; $i < $count; $i++) {
            if (!isset($clients[$client_index])) break;

            $client = $clients[$client_index];

            // تحديث العميل
            $this->db->where('id', $client['id']);
            $this->db->update($table, [
                'n3'         => $emp_info['n3'],
                'h4'         => $emp_info['h4'],
                'h5'         => $emp_info['h5'],
                'h7'         => $emp_info['h7'],
                'status_emp'  => 'مجهول',
                'status_emp1' => 'مجهول',
                'emp_det1'    => '',
                'emp_det'     => '',
                'date_emp'    => ''
            ]);

            $client_index++;
        }
    }

    return true;
}





public function distribute_clients_balanced_strict($project_id, $code)
{
    // جداول المشاريع
    $attribution_tables = [
        1  => 'attribution',
        5  => 'attribution1',
        55 => 'attribution2',
        4  => 'attribution3',
        3  => 'attribution4',
        33 => 'attribution5',
        6  => 'attribution6',
        7  => 'attribution7',
        2  => 'attribution8',
        8  => 'attribution9',
        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14',
        15 => 'attribution15'
    ];

    if (!isset($attribution_tables[$project_id])) {
        return false;
    }

    $table = $attribution_tables[$project_id];

    // 1. جلب العملاء المستهدفين فقط
    $clients = $this->db->query("
        SELECT * FROM $table 
        WHERE n3 = ? 
        ORDER BY h1 DESC
    ", [$code])->result_array();

    if (empty($clients)) {
        return false;
    }

    // 2. جلب الموظفين المؤهلين
    $eligible_employees = $this->db->query("
        SELECT a.n3, a.h4, a.h5, a.h7
        FROM $table a
        INNER JOIN users u ON a.n3 = u.username
        WHERE a.n3 != ?
        GROUP BY a.n3, a.h4, a.h5, a.h7
        ORDER BY a.n3 ASC
    ", [$code])->result_array();

    if (empty($eligible_employees)) {
        return false;
    }

    $employee_count = count($eligible_employees);
    $client_count   = count($clients);

    // التوزيع بالتساوي عددياً أولاً
    $base_share = floor($client_count / $employee_count);
    $extra = $client_count % $employee_count;

    // تجهيز هيكل توزيع الموظفين
    $employee_stats = [];
    foreach ($eligible_employees as $index => $emp) {
        $employee_stats[$index] = [
            'info' => $emp,
            'clients' => $base_share + ($extra > 0 ? 1 : 0),
            'assigned' => [],
            'total_debt' => 0
        ];
        if ($extra > 0) $extra--;
    }

    // 3. توزيع العملاء بالتساوي عددياً
    $client_index = 0;
    foreach ($employee_stats as $index => &$emp_stat) {
        for ($i = 0; $i < $emp_stat['clients']; $i++) {
            if (!isset($clients[$client_index])) break;
            $emp_stat['assigned'][] = $clients[$client_index];
            $emp_stat['total_debt'] += $clients[$client_index]['h1'];
            $client_index++;
        }
    }

    // 4. تحسين التوزيع بالمبالغ (نقل بعض العملاء بين الموظفين)
    $improved = true;
    while ($improved) {
        $improved = false;

        // ترتيب حسب المديونية
        usort($employee_stats, function($a, $b) {
            return $b['total_debt'] <=> $a['total_debt'];
        });

        $highest = &$employee_stats[0]; // أعلى مديونية
        $lowest  = &$employee_stats[count($employee_stats)-1]; // أقل مديونية

        // فرق المبالغ
        $diff = $highest['total_debt'] - $lowest['total_debt'];

        if ($diff > 100000) { // حد تعديل 100 ألف
            // نقل عميل كبير من الأعلى إلى الأدنى
            usort($highest['assigned'], function($a, $b) {
                return $b['h1'] <=> $a['h1'];
            });
            $transfer_client = array_shift($highest['assigned']);
            if ($transfer_client) {
                $highest['total_debt'] -= $transfer_client['h1'];
                $lowest['assigned'][] = $transfer_client;
                $lowest['total_debt'] += $transfer_client['h1'];
                $improved = true;
            }
        }
    }

    // 5. حفظ التوزيع في قاعدة البيانات
    foreach ($employee_stats as $emp_stat) {
        $emp_info = $emp_stat['info'];
        foreach ($emp_stat['assigned'] as $client) {
            $this->db->where('id', $client['id']);
            $this->db->update($table, [
                'n3'         => $emp_info['n3'],
                'h4'         => $emp_info['h4'],
                'h5'         => $emp_info['h5'],
                'h7'         => $emp_info['h7'],
                'status_emp'  => 'مجهول',
                'status_emp1' => 'مجهول',
                'emp_det1'    => '',
                'emp_det'     => '',
                'date_emp'    => ''
            ]);
        }
    }

    return true;
}



public function distribute_clients_balanced($project_id, $code)
{
    // خريطة جميع جداول attribution
    $attribution_tables = [
        1  => 'attribution',
        5  => 'attribution1',
        55 => 'attribution2',
        4  => 'attribution3',
        3  => 'attribution4',
        33 => 'attribution5',
        6  => 'attribution6',
        7  => 'attribution7',
        2  => 'attribution8',
        8  => 'attribution9',
        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14',
        15 => 'attribution15'
    ];

    if (!isset($attribution_tables[$project_id])) {
        return false;
    }

    $table = $attribution_tables[$project_id];

    // 1. جلب العملاء وترتيبهم حسب المديونية تنازلي
    $clients = $this->db->query("
        SELECT * FROM $table 
        WHERE n3 = ? 
        ORDER BY h1 DESC
    ", [$code])->result_array();

    if (empty($clients)) {
        return false;
    }

    // 2. جلب الموظفين المؤهلين
    $eligible_employees = $this->db->query("
        SELECT a.n3, a.h4, a.h5, a.h7
        FROM $table a
        INNER JOIN users u ON a.n3 = u.username
        WHERE a.n3 != ?
        GROUP BY a.n3, a.h4, a.h5, a.h7
        ORDER BY a.n3 ASC
    ", [$code])->result_array();

    if (empty($eligible_employees)) {
        return false;
    }

    $employee_count = count($eligible_employees);

    // أهداف التوزيع
    $target_clients = ceil(count($clients) / $employee_count);
    $target_debt    = ceil(array_sum(array_column($clients, 'h1')) / $employee_count);

    // مصفوفة إحصائيات الموظفين
    $employee_stats = [];
    foreach ($eligible_employees as $emp) {
        $employee_stats[] = [
            'info'       => $emp,
            'total_debt' => 0,
            'clients'    => 0
        ];
    }

    // 3. توزيع العملاء
    foreach ($clients as $client) {
        // اختيار الموظف الأقل وزن = توازن بين عدد العملاء والمبالغ
        usort($employee_stats, function($a, $b) use ($target_clients, $target_debt) {
            $scoreA = ($a['clients'] / $target_clients) + ($a['total_debt'] / $target_debt);
            $scoreB = ($b['clients'] / $target_clients) + ($b['total_debt'] / $target_debt);
            return $scoreA <=> $scoreB;
        });

        // تحديث العميل بالموظف المختار
        $chosen = &$employee_stats[0];
        $emp_info = $chosen['info'];

        $this->db->where('id', $client['id']);
        $this->db->update($table, [
            'n3'         => $emp_info['n3'],
            'h4'         => $emp_info['h4'],
            'h5'         => $emp_info['h5'],
            'h7'         => $emp_info['h7'],
            'status_emp'  => 'مجهول',
            'status_emp1' => 'مجهول',
            'emp_det1'    => '',
            'emp_det'     => '',
            'date_emp'    => ''
        ]);

        // تحديث إحصائيات الموظف
        $chosen['total_debt'] += $client['h1'];
        $chosen['clients']++;
    }

    return true;
}





public function distribute_clients_equal1111($project_id, $code)
{
    // جداول attribution
    $attribution_tables = [
        1  => 'attribution',
        5  => 'attribution1',
        55 => 'attribution2',
        4  => 'attribution3',
        3  => 'attribution4',
        33 => 'attribution5',
        6  => 'attribution6',
        7  => 'attribution7',
        2  => 'attribution8',
        8  => 'attribution9',
        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14',
        15 => 'attribution15'
    ];

    if (!isset($attribution_tables[$project_id])) {
        return false;
    }

    $table = $attribution_tables[$project_id];

    // 1. جلب العملاء المستهدفين وترتيبهم حسب المديونية h1 تنازليًا
    $clients = $this->db->query("
        SELECT * FROM $table 
        WHERE n3 = ? 
        ORDER BY h1 DESC
    ", [$code])->result_array();

    if (empty($clients)) {
        return false;
    }

    // 2. جلب الموظفين المؤهلين (باستثناء الكود)
    $eligible_employees = $this->db->query("
        SELECT a.n3, a.h4, a.h5, a.h7
        FROM $table a
        INNER JOIN users u ON a.n3 = u.username
        WHERE a.n3 != ?
        GROUP BY a.n3, a.h4, a.h5, a.h7
        ORDER BY a.n3 ASC
    ", [$code])->result_array();

    if (empty($eligible_employees)) {
        return false;
    }

    // تحضير مصفوفة لتتبع مجموع المبالغ وعدد العملاء لكل موظف
    $employee_stats = [];
    foreach ($eligible_employees as $index => $emp) {
        $employee_stats[$index] = [
            'info' => $emp,
            'total_debt' => 0,
            'clients' => 0
        ];
    }

    // 3. توزيع العملاء لتحقيق عدل المديونيات
    foreach ($clients as $client) {
        // ترتيب الموظفين حسب أقل مجموع مديونية ثم أقل عدد عملاء
        usort($employee_stats, function($a, $b) {
            if ($a['total_debt'] == $b['total_debt']) {
                return $a['clients'] - $b['clients'];
            }
            return $a['total_debt'] - $b['total_debt'];
        });

        // اختيار أول موظف (الأقل مديونية حاليًا)
        $chosen = &$employee_stats[0];
        $emp_info = $chosen['info'];

        // تحديث العميل ببيانات الموظف
        $this->db->where('id', $client['id']);
        $this->db->update($table, [
            'n3'         => $emp_info['n3'],
            'h4'         => $emp_info['h4'],
            'h5'         => $emp_info['h5'],
            'h7'         => $emp_info['h7'],
            'status_emp'  => 'مجهول',
            'status_emp1' => 'مجهول',
            'emp_det1'    => '',
            'emp_det'     => '',
            'date_emp'    => ''
        ]);

        // تحديث إحصائيات الموظف
        $chosen['total_debt'] += $client['h1'];
        $chosen['clients'] += 1;
    }

    return true;
}





public function assign_client_to_employee($project_id, $client_identity, $employee_username)
