public function distribute_clients_priority_allss($project_id, $code)
{
    $attribution_tables = [
        1  => 'attribution',
        5  => 'attribution1',
        55 => 'attribution2',
        4  => 'attribution3',
        3  => 'attribution4',
        33 => 'attribution5',
        6  => 'attribution6',
        7  => 'attribution7',
        2  => 'attribution8',
        8  => 'attribution9',
        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14',
        15 => 'attribution15'
    ];

    if (!isset($attribution_tables[$project_id])) {
        return false;
    }

    $table = $attribution_tables[$project_id];

    // 1. العملاء المراد توزيعهم
    $clients = $this->db->query("
        SELECT * FROM $table 
        WHERE n3 = ? 
        ORDER BY id ASC
    ", [$code])->result_array();

    if (empty($clients)) {
        return false;
    }

    // 2. الموظفين المؤهلين
    $eligible_employees = $this->db->query("
        SELECT DISTINCT a.n3, a.h4, a.h5, a.h7, a.category
        FROM $table a
        INNER JOIN users u ON a.n3 = u.username
        WHERE a.n3 != ?
    ", [$code])->result_array();

    if (empty($eligible_employees)) {
        return false;
    }

    // 3. حساب عدد العملاء الحالي وإجمالي المديونية لكل موظف
    foreach ($eligible_employees as &$employee) {
        $data = $this->db->query("
            SELECT COUNT(*) AS total_clients, IFNULL(SUM(h1),0) AS total_debt
            FROM $table 
            WHERE n3 = ?
        ", [$employee['n3']])->row();

        $employee['current_count'] = $data->total_clients;
        $employee['total_debt_sum'] = $data->total_debt;

        $employee['debt_distribution'] = [
            'below_50k'   => 0,
            '50k_100k'    => 0,
            '100k_150k'   => 0,
            'above_150k'  => 0
        ];
    }

    // 4. توزيع العملاء
    foreach ($clients as $client) {
        $debt = (float)$client['h1'];
        $debt_segment = 'above_150k';

        if ($debt < 50000) {
            $debt_segment = 'below_50k';
        } elseif ($debt >= 50000 && $debt < 100000) {
            $debt_segment = '50k_100k';
        } elseif ($debt >= 100000 && $debt < 150000) {
            $debt_segment = '100k_150k';
        }

        // فلترة حسب الفئة إذا متاحة
        $client_category = $client['category'];
        $filtered_employees = array_filter($eligible_employees, function ($emp) use ($client_category) {
            return $emp['category'] === $client_category || empty($client_category);
        });

        if (empty($filtered_employees)) {
            $filtered_employees = $eligible_employees;
        }

        // ترتيب حسب: إجمالي المديونية أولاً ثم عدد العملاء ثم شريحة الدين
        usort($filtered_employees, function ($a, $b) use ($debt_segment) {
            // قارن بإجمالي المديونية
            if ($a['total_debt_sum'] == $b['total_debt_sum']) {
                // إذا تساووا بالمديونية قارن بعدد العملاء
                if ($a['current_count'] == $b['current_count']) {
                    // إذا تساووا كمان، قارن بعدد العملاء بنفس شريحة الدين
                    return $a['debt_distribution'][$debt_segment] <=> $b['debt_distribution'][$debt_segment];
                }
                return $a['current_count'] <=> $b['current_count'];
            }
            return $a['total_debt_sum'] <=> $b['total_debt_sum'];
        });

        // اختيار الموظف
        $employee = &$filtered_employees[0];

        // تحديث العميل
        $this->db->where('id', $client['id']);
        $this->db->update($table, [
            'n3'         => $employee['n3'],
            'h4'         => $employee['h4'],
            'h5'         => $employee['h5'],
            'h7'         => $employee['h7'],
            'status_emp'  => 'مجهول',
            'status_emp1' => 'مجهول',
            'emp_det1'    => '',
            'emp_det'     => '',
            'date_emp'    => ''
        ]);

        // تحديث عدادات الموظف
        foreach ($eligible_employees as &$emp) {
            if ($emp['n3'] === $employee['n3']) {
                $emp['current_count']++;
                $emp['total_debt_sum'] += $debt;
                $emp['debt_distribution'][$debt_segment]++;
                break;
            }
        }
    }

    return true;
}










