function get_emkan($id) {
    $project = $this->session->userdata('project');
    $table = '';

    switch ($project) {
        case 1:  $table = 'emkan';   break;
        case 2:  $table = 'alahli';  break;
        case 3:  $table = 'alrajhi'; break;
        case 14:  $table = 'alrajhi'; break;
        case 4:  $table = 'alenma';  break;
        case 5:  $table = 'alriad';  break;
        case 11: $table = 'alahli';  break;
        default: return null; // إذا لم يكن المشروع معروفًا
    }

    $sql = "SELECT * FROM $table WHERE n1 = ?";
    $query = $this->db->query($sql, [$id]);
    return $query->row_array();
}


