      function cuntt_attributionh45215() {
    $username = $this->session->userdata('username'); // رقم الموظف الحالي
    $current_month = date('Y/m'); // تنسيق الشهر الحالي

    $table = $this->attribution;

    $sql = "
        SELECT COUNT(*) AS total
        FROM $table a
        LEFT JOIN (
            SELECT x1
            FROM employee_follow_up
            WHERE DATE_FORMAT(n4, '%Y/%m') = ?
            GROUP BY x1
        ) f ON a.n1 = f.x1
        WHERE a.n3 = ?
        AND f.x1 IS NULL
    ";

    $query = $this->db->query($sql, [$current_month, $username]);
    $row = $query->row();
    return $row ? $row->total : 0;
}

function cuntt_attributionh4521511() {
    $username = $this->session->userdata('username'); // رقم الموظف الحالي
    $current_month = date('Y/m'); // صيغة التاريخ: yyyy/mm

    $table = $this->attribution;

    $sql = "
        SELECT COUNT(*) AS total
        FROM $table a
        LEFT JOIN (
            SELECT x1
            FROM employee_follow_up
            WHERE DATE_FORMAT(n4, '%Y/%m') = ?
            AND x3 = ?
            GROUP BY x1
        ) f ON a.n1 = f.x1
        WHERE a.h4 = ?
        AND f.x1 IS NULL
    ";

    $query = $this->db->query($sql, [$current_month, $username, $username]);
    $row = $query->row();
    return $row ? $row->total : 0;
}

function cuntt_attributionh45215111() {
    $project = $this->session->userdata('project'); // كود المشروع الحالي
    $current_month = date('Y/m'); // صيغة التاريخ yyyy/mm
    $table = $this->attribution;

    $sql = "
        SELECT COUNT(*) AS total
        FROM $table a
        LEFT JOIN (
            SELECT x1
            FROM employee_follow_up
            WHERE DATE_FORMAT(n4, '%Y/%m') = ?
            AND project = ?
            GROUP BY x1
        ) f ON a.n1 = f.x1
        WHERE a.project_id = ?
        AND f.x1 IS NULL
    ";

    $query = $this->db->query($sql, [$current_month, $project, $project]);
    $row = $query->row();
    return $row ? $row->total : 0;
}





