      function update_complaints_emkan($id){

           date_default_timezone_set('Asia/Riyadh');
           $d1=date("Y/m/d");
           $d='2';
           $m=date("Y/m");
           $y=date("Y");
           $day=date("l");
           $time = date("H:i:s"); 
           $data = array(
                  
                  'date2' => $d1,
                  'time2' => $time,
                  'status' => $d,
                  'note1' => $this->input->POST('note'),
                  
            );
            $this->db->where('id', $id);
            return $this->db->update('complaints_emkan', $data);
       }



