    function sum_employee_reimbursements112125($username) {

    // ضبط المنطقة الزمنية
    date_default_timezone_set('Asia/Riyadh');
    
    // تحديد تاريخ اليوم
    $today = date('Y/m/d'); // اليوم الحالي بصيغة YYYY/MM/DD
    $s = 1;

    // إعداد شرط الاستعلام
    $this->db->select_sum('n2'); // مجموع العمود n2
    $this->db->where('x3', $username); // شرط اسم المستخدم
    $this->db->where('status', $s); // شرط الحالة
    $this->db->where('n8', $today); // شرط تاريخ اليوم

    // تنفيذ الاستعلام
    $result = $this->db->get('employee_reimbursements')->row();

    // إرجاع النتيجة
    return $result->n2 ?? 0; // إرجاع 0 إذا كانت النتيجة فارغة
}

