public function get_next_n1($current_id) {
     $username = $this->session->userdata('username');
    // تنفيذ الاستعلام

    // $s="0";

    $this->db->select('n1'); // تحديد العمود المطلوب
    $this->db->from($this->attribution); // تحديد الجدول
    $this->db->where('id >', $current_id); // شرط لجلب القيم التي تلي id الحالي
    $this->db->where('n3', $username); // شرط لمطابقة اسم المستخدم
   // $this->db->where('status', $s); // شرط لمطابقة اسم المستخدم
    $this->db->order_by('id', 'ASC'); // ترتيب تصاعدي حسب عمود id
    $this->db->limit(1); // جلب سجل واحد فقط
    $query = $this->db->get();

    // التحقق من وجود نتيجة
    if ($query->num_rows() > 0) {
        return $query->row()->n1; // إرجاع القيمة التالية لـ n1
    }

    return null; // إذا لم توجد قيمة تالية
}

public function get_next_n11($current_id) {
    $username = $this->session->userdata('username'); // الحصول على اسم المستخدم من الجلسة

    // تنفيذ الاستعلام
    $this->db->select('n1'); // تحديد العمود المطلوب
    $this->db->from($this->attribution); // تحديد الجدول
    $this->db->where('id >', $current_id); // شرط لجلب القيم التي تلي id الحالي
    $this->db->where('n3', $username); // شرط لمطابقة اسم المستخدم
    $this->db->where('status', 0); // شرط لمطابقة status = 0
    $this->db->order_by('id', 'ASC'); // ترتيب تصاعدي حسب عمود id
    $this->db->limit(1); // جلب سجل واحد فقط
    $query = $this->db->get();

    // التحقق من وجود نتيجة
    if ($query->num_rows() > 0) {
        return $query->row()->n1; // إرجاع القيمة التالية لـ n1
    }

    return null; // إذا لم توجد قيمة تالية
}







public function get_previous_n1($current_id) {
    $username = $this->session->userdata('username'); // الحصول على اسم المستخدم من الجلسة
    //$s=0;

    // تنفيذ الاستعلام
    $this->db->select('n1'); // تحديد العمود المطلوب
    $this->db->from($this->attribution); // تحديد الجدول
    $this->db->where('id <', $current_id); // شرط لجلب القيم التي تسبق id الحالي
    $this->db->where('n3', $username); // شرط لمطابقة اسم المستخدم
   // $this->db->where('status', $s); // شرط لمطابقة اسم المستخدم
    $this->db->order_by('id', 'DESC'); // ترتيب تنازلي حسب عمود id للحصول على القيمة السابقة
    $this->db->limit(1); // جلب سجل واحد فقط
    $query = $this->db->get();

    // التحقق من وجود نتيجة
    if ($query->num_rows() > 0) {
        return $query->row()->n1; // إرجاع القيمة السابقة لـ n1
    }

    return null; // إذا لم توجد قيمة سابقة
}

public function get_previous_n11($current_id) {
    $username = $this->session->userdata('username'); // الحصول على اسم المستخدم من الجلسة

    // تنفيذ الاستعلام
    $this->db->select('n1'); // تحديد العمود المطلوب
    $this->db->from($this->attribution); // تحديد الجدول
    $this->db->where('id <', $current_id); // شرط لجلب القيم التي تسبق id الحالي
    $this->db->where('n3', $username); // شرط لمطابقة اسم المستخدم
    $this->db->where('status', 0); // شرط لمطابقة status = 0
    $this->db->order_by('id', 'DESC'); // ترتيب تنازلي حسب عمود id للحصول على القيمة السابقة
    $this->db->limit(1); // جلب سجل واحد فقط
    $query = $this->db->get();

    // التحقق من وجود نتيجة
    if ($query->num_rows() > 0) {
        return $query->row()->n1; // إرجاع القيمة السابقة لـ n1
    }

    return null; // إذا لم توجد قيمة سابقة
}

public function has_clients_with_status_6($employee_id)
{
    $table = $this->attribution;

    // الحصول على أسماء الأعمدة من الجدول
    $fields = $this->db->list_fields($table);

    $this->db->where('n3', $employee_id); // الرقم الوظيفي

    // الشرط الأول: إذا كان العمود status2 موجود، نضيف شرط status2 = 6
    if (in_array('status2', $fields)) {
        $this->db->where('status2', 6);
    }

    // الشرط الثاني: إذا كان العمود status6 موجود، نضيف شرط بأن يكون غير فارغ
    if (in_array('status6', $fields)) {
        $this->db->where('status6 !=', '');
    }

    // تنفيذ الاستعلام
    $this->db->from($table);
    return $this->db->count_all_results() > 0;
}
















     

 



